{
  "name": "@node/newton-sim",
  "version": "1.0.0",
  "description": "Interactive Newton's laws simulator with pendulum, projectile motion, and spring-mass systems",
  "main": "index.ts",
  "modnet": {
    "contentType": "science",
    "structure": "steps",
    "mechanics": ["track", "chart"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "@plaited/template": "latest"
  }
}

{
  "pendulum": {
    "earth": { "length": 2, "gravity": 9.81, "initialAngle": 45 },
    "moon": { "length": 2, "gravity": 1.62, "initialAngle": 45 },
    "jupiter": { "length": 2, "gravity": 24.79, "initialAngle": 45 },
    "longPendulum": { "length": 5, "gravity": 9.81, "initialAngle": 30 }
  },
  "projectile": {
    "optimal": { "angle": 45, "velocity": 20, "gravity": 9.81 },
    "highAngle": { "angle": 70, "velocity": 25, "gravity": 9.81 },
    "lowAngle": { "angle": 20, "velocity": 30, "gravity": 9.81 },
    "lunar": { "angle": 45, "velocity": 15, "gravity": 1.62 }
  },
  "spring": {
    "soft": { "springConstant": 5, "mass": 1, "initialDisplacement": 2 },
    "stiff": { "springConstant": 40, "mass": 1, "initialDisplacement": 1 },
    "heavy": { "springConstant": 10, "mass": 8, "initialDisplacement": 1.5 },
    "light": { "springConstant": 10, "mass": 0.2, "initialDisplacement": 1 }
  }
}

export type SimulationType = 'pendulum' | 'projectile' | 'spring'

export type PendulumParams = {
  length: number
  gravity: number
  initialAngle: number
  damping: number
}

export type ProjectileParams = {
  angle: number
  initialVelocity: number
  gravity: number
}

export type SpringParams = {
  springConstant: number
  mass: number
  initialDisplacement: number
  damping: number
}

export type SimulationConfig = {
  type: SimulationType
  speed: number
  running: boolean
}

export type RealTimeValues = {
  time: number
  position: { x: number; y: number }
  velocity: { x: number; y: number; magnitude: number }
  acceleration: { magnitude: number }
}

import type { PendulumParams, ProjectileParams, SpringParams } from './types'

type StateVector = [number, number]
type DerivativeFn = (state: StateVector, t: number) => StateVector

const rk4Step = (
  state: StateVector,
  t: number,
  dt: number,
  derivs: DerivativeFn
): StateVector => {
  const k1 = derivs(state, t)
  const k2 = derivs(
    [state[0] + k1[0] * dt / 2, state[1] + k1[1] * dt / 2],
    t + dt / 2
  )
  const k3 = derivs(
    [state[0] + k2[0] * dt / 2, state[1] + k2[1] * dt / 2],
    t + dt / 2
  )
  const k4 = derivs(
    [state[0] + k3[0] * dt, state[1] + k3[1] * dt],
    t + dt
  )
  return [
    state[0] + (dt / 6) * (k1[0] + 2 * k2[0] + 2 * k3[0] + k4[0]),
    state[1] + (dt / 6) * (k1[1] + 2 * k2[1] + 2 * k3[1] + k4[1]),
  ]
}

export const pendulumDerivatives = (
  params: PendulumParams
): DerivativeFn => {
  const { length, gravity, damping } = params
  return (state: StateVector): StateVector => {
    const [theta, omega] = state
    const dTheta = omega
    const dOmega = -(gravity / length) * Math.sin(theta) - damping * omega
    return [dTheta, dOmega]
  }
}

export const stepPendulum = (
  theta: number,
  omega: number,
  params: PendulumParams,
  dt: number,
  t: number
): { theta: number; omega: number; acceleration: number } => {
  const derivs = pendulumDerivatives(params)
  const [newTheta, newOmega] = rk4Step([theta, omega], t, dt, derivs)
  const acceleration = -(params.gravity / params.length) * Math.sin(newTheta) - params.damping * newOmega
  return { theta: newTheta, omega: newOmega, acceleration }
}

export const pendulumPosition = (
  theta: number,
  length: number
): { x: number; y: number } => ({
  x: length * Math.sin(theta),
  y: length * Math.cos(theta),
})

export const stepProjectile = (
  x: number,
  y: number,
  vx: number,
  vy: number,
  params: ProjectileParams,
  dt: number
): { x: number; y: number; vx: number; vy: number } => ({
  x: x + vx * dt,
  y: y + vy * dt,
  vx,
  vy: vy - params.gravity * dt,
})

export const launchProjectile = (
  params: ProjectileParams
): { vx: number; vy: number } => {
  const rad = (params.angle * Math.PI) / 180
  return {
    vx: params.initialVelocity * Math.cos(rad),
    vy: params.initialVelocity * Math.sin(rad),
  }
}

export const springDerivatives = (
  params: SpringParams
): DerivativeFn => {
  const { springConstant, mass, damping } = params
  return (state: StateVector): StateVector => {
    const [x, v] = state
    const dx = v
    const dv = -(springConstant / mass) * x - damping * v
    return [dx, dv]
  }
}

export const stepSpring = (
  displacement: number,
  velocity: number,
  params: SpringParams,
  dt: number,
  t: number
): { displacement: number; velocity: number; acceleration: number } => {
  const derivs = springDerivatives(params)
  const [newDisp, newVel] = rk4Step([displacement, velocity], t, dt, derivs)
  const acceleration = -(params.springConstant / params.mass) * newDisp - params.damping * newVel
  return { displacement: newDisp, velocity: newVel, acceleration }
}

import { h, Fragment } from '@plaited/template'
import { createSSR } from '@plaited/template'

const clientScript = `
'use strict';

// ── RK4 Integrator ──────────────────────────────────────────────────────
const rk4 = (state, t, dt, derivs) => {
  const k1 = derivs(state, t);
  const k2 = derivs([state[0]+k1[0]*dt/2, state[1]+k1[1]*dt/2], t+dt/2);
  const k3 = derivs([state[0]+k2[0]*dt/2, state[1]+k2[1]*dt/2], t+dt/2);
  const k4 = derivs([state[0]+k3[0]*dt, state[1]+k3[1]*dt], t+dt);
  return [
    state[0] + (dt/6)*(k1[0]+2*k2[0]+2*k3[0]+k4[0]),
    state[1] + (dt/6)*(k1[1]+2*k2[1]+2*k3[1]+k4[1])
  ];
};

// ── Simulation State ─────────────────────────────────────────────────────
const sim = {
  active: 'pendulum',
  running: false,
  speed: 1,
  time: 0,
  lastFrame: 0,
  animId: null,

  pendulum: {
    length: 2, gravity: 9.81, initialAngle: 45, damping: 0.002,
    theta: Math.PI/4, omega: 0, trail: []
  },
  projectile: {
    angle: 45, velocity: 20, gravity: 9.81,
    x: 0, y: 0, vx: 0, vy: 0,
    trajectory: [], launched: false, landed: false
  },
  spring: {
    k: 10, mass: 1, initialDisp: 1.5, damping: 0.02,
    disp: 1.5, vel: 0, trail: []
  }
};

// ── DOM refs ─────────────────────────────────────────────────────────────
const $ = (id) => document.getElementById(id);

// ── Physics ──────────────────────────────────────────────────────────────
const stepPendulum = (dt) => {
  const p = sim.pendulum;
  const derivs = (s) => [
    s[1],
    -(p.gravity / p.length) * Math.sin(s[0]) - p.damping * s[1]
  ];
  const [theta, omega] = rk4([p.theta, p.omega], sim.time, dt, derivs);
  p.theta = theta;
  p.omega = omega;
  const x = p.length * Math.sin(theta);
  const y = p.length * Math.cos(theta);
  p.trail.push({ x, y });
  if (p.trail.length > 200) p.trail.shift();
};

const stepProjectile = (dt) => {
  const p = sim.projectile;
  if (!p.launched) {
    const rad = p.angle * Math.PI / 180;
    p.vx = p.velocity * Math.cos(rad);
    p.vy = p.velocity * Math.sin(rad);
    p.x = 0; p.y = 0;
    p.launched = true;
    p.landed = false;
    p.trajectory = [{ x: 0, y: 0 }];
  }
  if (p.landed) return;
  p.x += p.vx * dt;
  p.y += p.vy * dt;
  p.vy -= p.gravity * dt;
  if (p.y <= 0 && sim.time > 0.01) {
    p.y = 0;
    p.landed = true;
  }
  p.trajectory.push({ x: p.x, y: p.y });
};

const stepSpring = (dt) => {
  const s = sim.spring;
  const derivs = (st) => [
    st[1],
    -(s.k / s.mass) * st[0] - s.damping * st[1]
  ];
  const [disp, vel] = rk4([s.disp, s.vel], sim.time, dt, derivs);
  s.disp = disp;
  s.vel = vel;
  s.trail.push({ t: sim.time, x: disp });
  if (s.trail.length > 300) s.trail.shift();
};

// ── Rendering ────────────────────────────────────────────────────────────
const renderPendulum = () => {
  const svg = $('sim-canvas');
  const p = sim.pendulum;
  const cx = 300, cy = 60;
  const scale = 80;
  const bobX = cx + p.length * Math.sin(p.theta) * scale;
  const bobY = cy + p.length * Math.cos(p.theta) * scale;

  let html = '';
  // Background grid
  html += '<line x1="300" y1="50" x2="300" y2="390" stroke="#1a2a3a" stroke-width="1" stroke-dasharray="4"/>';
  // Pivot
  html += '<circle cx="' + cx + '" cy="' + cy + '" r="6" fill="#64748b"/>';
  html += '<rect x="270" y="45" width="60" height="8" rx="2" fill="#475569"/>';
  // Trail
  if (p.trail.length > 1) {
    html += '<polyline points="';
    for (let i = 0; i < p.trail.length; i++) {
      const tx = cx + p.trail[i].x * scale;
      const ty = cy + p.trail[i].y * scale;
      html += tx.toFixed(1) + ',' + ty.toFixed(1) + ' ';
    }
    html += '" fill="none" stroke="rgba(59,130,246,0.3)" stroke-width="2"/>';
  }
  // Rod
  html += '<line x1="' + cx + '" y1="' + cy + '" x2="' + bobX.toFixed(1) + '" y2="' + bobY.toFixed(1) + '" stroke="#94a3b8" stroke-width="3" stroke-linecap="round"/>';
  // Bob
  html += '<circle cx="' + bobX.toFixed(1) + '" cy="' + bobY.toFixed(1) + '" r="16" fill="#3b82f6" stroke="#60a5fa" stroke-width="2"/>';
  // Velocity vector
  const velScale = 15;
  const vx = p.length * p.omega * Math.cos(p.theta) * velScale;
  const vy = -p.length * p.omega * Math.sin(p.theta) * velScale;
  if (Math.abs(p.omega) > 0.01) {
    html += '<line x1="' + bobX.toFixed(1) + '" y1="' + bobY.toFixed(1) + '" x2="' + (bobX+vx).toFixed(1) + '" y2="' + (bobY+vy).toFixed(1) + '" stroke="#22c55e" stroke-width="2.5" marker-end="url(#arrowGreen)"/>';
  }
  // Angle arc
  if (Math.abs(p.theta) > 0.03) {
    const arcR = 40;
    const endX = cx + arcR * Math.sin(p.theta);
    const endY = cy + arcR * Math.cos(p.theta);
    const large = Math.abs(p.theta) > Math.PI ? 1 : 0;
    const sweep = p.theta > 0 ? 1 : 0;
    html += '<path d="M ' + cx + ' ' + (cy+arcR) + ' A ' + arcR + ' ' + arcR + ' 0 ' + large + ' ' + sweep + ' ' + endX.toFixed(1) + ' ' + endY.toFixed(1) + '" fill="none" stroke="#fbbf24" stroke-width="1.5" stroke-dasharray="3"/>';
    const labelX = cx + (arcR+12) * Math.sin(p.theta/2);
    const labelY = cy + (arcR+12) * Math.cos(p.theta/2);
    html += '<text x="' + labelX.toFixed(1) + '" y="' + labelY.toFixed(1) + '" fill="#fbbf24" font-size="12" text-anchor="middle">' + (p.theta * 180 / Math.PI).toFixed(1) + '\\u00B0</text>';
  }
  svg.innerHTML = html;

  // Values
  const posX = p.length * Math.sin(p.theta);
  const posY = p.length * Math.cos(p.theta);
  const vel = p.length * Math.abs(p.omega);
  const acc = Math.abs(-(p.gravity / p.length) * Math.sin(p.theta));
  $('val-pos').textContent = 'x: ' + posX.toFixed(3) + ' m, y: ' + posY.toFixed(3) + ' m';
  $('val-vel').textContent = vel.toFixed(3) + ' m/s';
  $('val-acc').textContent = (acc * p.length).toFixed(3) + ' m/s\\u00B2';
  $('val-time').textContent = sim.time.toFixed(2) + ' s';
  $('val-extra').textContent = '\\u03B8: ' + (p.theta * 180 / Math.PI).toFixed(2) + '\\u00B0, \\u03C9: ' + p.omega.toFixed(3) + ' rad/s';
};

const renderProjectile = () => {
  const svg = $('sim-canvas');
  const p = sim.projectile;
  const ox = 40, oy = 360;
  const scaleX = 8, scaleY = 8;

  let html = '';
  // Ground
  html += '<line x1="30" y1="360" x2="590" y2="360" stroke="#475569" stroke-width="2"/>';
  for (let i = 0; i <= 560; i += 40) {
    html += '<line x1="' + (30+i) + '" y1="360" x2="' + (20+i) + '" y2="370" stroke="#475569" stroke-width="1"/>';
  }
  // Grid lines
  for (let g = 0; g <= 40; g += 10) {
    const gy = oy - g * scaleY;
    html += '<line x1="30" y1="' + gy + '" x2="590" y2="' + gy + '" stroke="#1a2a3a" stroke-width="0.5"/>';
    html += '<text x="22" y="' + (gy+4) + '" fill="#64748b" font-size="9" text-anchor="end">' + g + '</text>';
  }
  for (let gx = 0; gx <= 65; gx += 10) {
    const px = ox + gx * scaleX;
    html += '<line x1="' + px + '" y1="30" x2="' + px + '" y2="360" stroke="#1a2a3a" stroke-width="0.5"/>';
    html += '<text x="' + px + '" y="375" fill="#64748b" font-size="9" text-anchor="middle">' + gx + '</text>';
  }
  // Launcher
  const rad = p.angle * Math.PI / 180;
  const launchLen = 30;
  html += '<line x1="' + ox + '" y1="' + oy + '" x2="' + (ox + launchLen*Math.cos(rad)).toFixed(1) + '" y2="' + (oy - launchLen*Math.sin(rad)).toFixed(1) + '" stroke="#f59e0b" stroke-width="4" stroke-linecap="round"/>';
  // Trajectory
  if (p.trajectory.length > 1) {
    html += '<polyline points="';
    for (let i = 0; i < p.trajectory.length; i++) {
      const tx = ox + p.trajectory[i].x * scaleX;
      const ty = oy - p.trajectory[i].y * scaleY;
      if (ty <= oy) html += tx.toFixed(1) + ',' + ty.toFixed(1) + ' ';
    }
    html += '" fill="none" stroke="rgba(239,68,68,0.5)" stroke-width="2"/>';
    // Dots along trajectory
    for (let i = 0; i < p.trajectory.length; i += Math.max(1, Math.floor(p.trajectory.length / 30))) {
      const tx = ox + p.trajectory[i].x * scaleX;
      const ty = oy - p.trajectory[i].y * scaleY;
      if (ty <= oy) html += '<circle cx="' + tx.toFixed(1) + '" cy="' + ty.toFixed(1) + '" r="2" fill="rgba(239,68,68,0.6)"/>';
    }
  }
  // Current position
  if (p.launched) {
    const px = ox + p.x * scaleX;
    const py = oy - p.y * scaleY;
    if (py <= oy) {
      html += '<circle cx="' + px.toFixed(1) + '" cy="' + py.toFixed(1) + '" r="8" fill="#ef4444" stroke="#f87171" stroke-width="2"/>';
      // Velocity vector
      const vs = 1.5;
      html += '<line x1="' + px.toFixed(1) + '" y1="' + py.toFixed(1) + '" x2="' + (px+p.vx*vs).toFixed(1) + '" y2="' + (py-p.vy*vs).toFixed(1) + '" stroke="#22c55e" stroke-width="2" marker-end="url(#arrowGreen)"/>';
    }
  }
  // Max height indicator
  if (p.trajectory.length > 2) {
    let maxH = 0, maxHx = 0;
    for (const pt of p.trajectory) { if (pt.y > maxH) { maxH = pt.y; maxHx = pt.x; } }
    if (maxH > 0.5) {
      const mhx = ox + maxHx * scaleX;
      const mhy = oy - maxH * scaleY;
      html += '<line x1="' + mhx.toFixed(1) + '" y1="' + mhy.toFixed(1) + '" x2="' + mhx.toFixed(1) + '" y2="' + oy + '" stroke="#fbbf24" stroke-width="1" stroke-dasharray="4"/>';
      html += '<text x="' + (mhx+5).toFixed(1) + '" y="' + (mhy-5).toFixed(1) + '" fill="#fbbf24" font-size="11">' + maxH.toFixed(1) + 'm</text>';
    }
  }
  svg.innerHTML = html;

  // Values
  const speed = Math.sqrt(p.vx*p.vx + p.vy*p.vy);
  $('val-pos').textContent = 'x: ' + p.x.toFixed(2) + ' m, y: ' + p.y.toFixed(2) + ' m';
  $('val-vel').textContent = speed.toFixed(2) + ' m/s (vx: ' + p.vx.toFixed(2) + ', vy: ' + p.vy.toFixed(2) + ')';
  $('val-acc').textContent = p.gravity.toFixed(2) + ' m/s\\u00B2 (downward)';
  $('val-time').textContent = sim.time.toFixed(2) + ' s';
  const range = p.landed ? p.x.toFixed(2) + ' m' : '...';
  let maxH2 = 0;
  for (const pt of p.trajectory) { if (pt.y > maxH2) maxH2 = pt.y; }
  $('val-extra').textContent = 'Range: ' + range + ', Max Height: ' + maxH2.toFixed(2) + ' m';
};

const renderSpring = () => {
  const svg = $('sim-canvas');
  const s = sim.spring;
  const wallX = 60, cy = 200, eqX = 300;
  const scale = 60;
  const massX = eqX + s.disp * scale;

  let html = '';
  // Wall
  html += '<rect x="40" y="140" width="20" height="120" fill="#475569" rx="2"/>';
  for (let i = 0; i < 6; i++) {
    const hy = 145 + i * 20;
    html += '<line x1="40" y1="' + hy + '" x2="30" y2="' + (hy+10) + '" stroke="#475569" stroke-width="1.5"/>';
  }
  // Equilibrium line
  html += '<line x1="' + eqX + '" y1="140" x2="' + eqX + '" y2="260" stroke="#fbbf24" stroke-width="1" stroke-dasharray="4"/>';
  html += '<text x="' + eqX + '" y="135" fill="#fbbf24" font-size="10" text-anchor="middle">equilibrium</text>';
  // Spring coils
  const coils = 12;
  const springStart = wallX;
  const springEnd = massX - 25;
  const coilWidth = (springEnd - springStart) / coils;
  let springPath = 'M ' + springStart + ' ' + cy;
  for (let i = 0; i < coils; i++) {
    const x1 = springStart + (i + 0.25) * coilWidth;
    const x2 = springStart + (i + 0.75) * coilWidth;
    const x3 = springStart + (i + 1) * coilWidth;
    const amp = 18;
    springPath += ' L ' + x1.toFixed(1) + ' ' + (cy - amp);
    springPath += ' L ' + x2.toFixed(1) + ' ' + (cy + amp);
    springPath += ' L ' + x3.toFixed(1) + ' ' + cy;
  }
  html += '<path d="' + springPath + '" fill="none" stroke="#60a5fa" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/>';
  // Mass block
  html += '<rect x="' + (massX-25).toFixed(1) + '" y="' + (cy-25) + '" width="50" height="50" rx="4" fill="#3b82f6" stroke="#60a5fa" stroke-width="2"/>';
  html += '<text x="' + massX.toFixed(1) + '" y="' + (cy+5) + '" fill="white" font-size="13" text-anchor="middle" font-weight="bold">' + s.mass.toFixed(1) + 'kg</text>';
  // Floor
  html += '<line x1="30" y1="226" x2="590" y2="226" stroke="#334155" stroke-width="1.5"/>';
  // Velocity arrow
  if (Math.abs(s.vel) > 0.02) {
    const vs = 20;
    html += '<line x1="' + massX.toFixed(1) + '" y1="' + (cy+40) + '" x2="' + (massX + s.vel*vs).toFixed(1) + '" y2="' + (cy+40) + '" stroke="#22c55e" stroke-width="2.5" marker-end="url(#arrowGreen)"/>';
    html += '<text x="' + (massX + s.vel*vs/2).toFixed(1) + '" y="' + (cy+55) + '" fill="#22c55e" font-size="10" text-anchor="middle">v</text>';
  }
  // Force arrow
  const force = -s.k * s.disp;
  if (Math.abs(force) > 0.1) {
    const fs = 2;
    html += '<line x1="' + massX.toFixed(1) + '" y1="' + (cy-40) + '" x2="' + (massX + force*fs).toFixed(1) + '" y2="' + (cy-40) + '" stroke="#f59e0b" stroke-width="2.5" marker-end="url(#arrowYellow)"/>';
    html += '<text x="' + (massX + force*fs/2).toFixed(1) + '" y="' + (cy-48) + '" fill="#f59e0b" font-size="10" text-anchor="middle">F</text>';
  }
  // Displacement indicator
  if (Math.abs(s.disp) > 0.01) {
    html += '<line x1="' + eqX + '" y1="' + (cy+70) + '" x2="' + massX.toFixed(1) + '" y2="' + (cy+70) + '" stroke="#a78bfa" stroke-width="1.5" marker-end="url(#arrowPurple)"/>';
    html += '<text x="' + ((eqX+massX)/2).toFixed(1) + '" y="' + (cy+85) + '" fill="#a78bfa" font-size="10" text-anchor="middle">' + s.disp.toFixed(2) + ' m</text>';
  }
  // Displacement-time graph (mini)
  if (s.trail.length > 2) {
    const gx = 350, gy = 80, gw = 220, gh = 60;
    html += '<rect x="' + gx + '" y="' + (gy-gh/2) + '" width="' + gw + '" height="' + gh + '" fill="rgba(15,23,42,0.6)" rx="4" stroke="#334155" stroke-width="1"/>';
    html += '<line x1="' + gx + '" y1="' + gy + '" x2="' + (gx+gw) + '" y2="' + gy + '" stroke="#334155" stroke-width="0.5"/>';
    html += '<text x="' + (gx+gw/2) + '" y="' + (gy-gh/2-4) + '" fill="#94a3b8" font-size="9" text-anchor="middle">displacement vs time</text>';
    const tMin = s.trail[0].t, tMax = s.trail[s.trail.length-1].t;
    const tRange = Math.max(tMax - tMin, 0.1);
    let maxD = 0;
    for (const pt of s.trail) { if (Math.abs(pt.x) > maxD) maxD = Math.abs(pt.x); }
    maxD = Math.max(maxD, 0.1);
    let pts = '';
    for (const pt of s.trail) {
      const px = gx + ((pt.t - tMin) / tRange) * gw;
      const py = gy - (pt.x / maxD) * (gh/2 - 4);
      pts += px.toFixed(1) + ',' + py.toFixed(1) + ' ';
    }
    html += '<polyline points="' + pts + '" fill="none" stroke="#a78bfa" stroke-width="1.5"/>';
  }
  svg.innerHTML = html;

  // Values
  const acc = -(s.k / s.mass) * s.disp;
  $('val-pos').textContent = 'displacement: ' + s.disp.toFixed(3) + ' m';
  $('val-vel').textContent = s.vel.toFixed(3) + ' m/s';
  $('val-acc').textContent = acc.toFixed(3) + ' m/s\\u00B2';
  $('val-time').textContent = sim.time.toFixed(2) + ' s';
  const omega = Math.sqrt(s.k / s.mass);
  const period = 2 * Math.PI / omega;
  $('val-extra').textContent = 'Period: ' + period.toFixed(3) + ' s, \\u03C9: ' + omega.toFixed(3) + ' rad/s, F: ' + (s.k * s.disp).toFixed(2) + ' N';
};

// ── Animation Loop ───────────────────────────────────────────────────────
const DT = 1 / 120;

const animate = (timestamp) => {
  if (!sim.running) return;
  if (!sim.lastFrame) sim.lastFrame = timestamp;
  const elapsed = Math.min((timestamp - sim.lastFrame) / 1000, 0.05);
  sim.lastFrame = timestamp;

  const steps = Math.max(1, Math.round(elapsed / DT * sim.speed));
  const actualDt = DT;

  for (let i = 0; i < steps; i++) {
    sim.time += actualDt;
    if (sim.active === 'pendulum') stepPendulum(actualDt);
    else if (sim.active === 'projectile') stepProjectile(actualDt);
    else if (sim.active === 'spring') stepSpring(actualDt);
  }

  if (sim.active === 'pendulum') renderPendulum();
  else if (sim.active === 'projectile') renderProjectile();
  else if (sim.active === 'spring') renderSpring();

  sim.animId = requestAnimationFrame(animate);
};

// ── Controls ─────────────────────────────────────────────────────────────
const play = () => {
  if (sim.active === 'projectile' && !sim.projectile.launched) {
    sim.projectile.launched = false;
  }
  sim.running = true;
  sim.lastFrame = 0;
  sim.animId = requestAnimationFrame(animate);
  $('btn-play').textContent = 'Pause';
};

const pause = () => {
  sim.running = false;
  if (sim.animId) cancelAnimationFrame(sim.animId);
  $('btn-play').textContent = 'Play';
};

const togglePlay = () => {
  if (sim.running) pause(); else play();
};

const resetSim = () => {
  pause();
  sim.time = 0;
  if (sim.active === 'pendulum') {
    const p = sim.pendulum;
    p.theta = p.initialAngle * Math.PI / 180;
    p.omega = 0;
    p.trail = [];
  } else if (sim.active === 'projectile') {
    const p = sim.projectile;
    p.x = 0; p.y = 0; p.vx = 0; p.vy = 0;
    p.trajectory = [];
    p.launched = false;
    p.landed = false;
  } else if (sim.active === 'spring') {
    const s = sim.spring;
    s.disp = s.initialDisp;
    s.vel = 0;
    s.trail = [];
  }
  renderActive();
};

const renderActive = () => {
  if (sim.active === 'pendulum') renderPendulum();
  else if (sim.active === 'projectile') renderProjectile();
  else if (sim.active === 'spring') renderSpring();
};

const switchTab = (tab) => {
  pause();
  sim.active = tab;
  sim.time = 0;
  document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
  document.querySelector('[data-tab="' + tab + '"]').classList.add('active');
  // Show/hide param panels
  document.querySelectorAll('.param-panel').forEach(p => p.style.display = 'none');
  $('params-' + tab).style.display = 'flex';
  resetSim();
};

const updateSpeed = (val) => {
  sim.speed = parseFloat(val);
  $('speed-label').textContent = sim.speed.toFixed(2) + 'x';
};

// ── Parameter Handlers ───────────────────────────────────────────────────
const bindSlider = (id, callback) => {
  const el = $(id);
  if (!el) return;
  el.addEventListener('input', (e) => {
    callback(parseFloat(e.target.value));
    if (!sim.running) renderActive();
  });
};

const init = () => {
  // Tab buttons
  document.querySelectorAll('.tab-btn').forEach(btn => {
    btn.addEventListener('click', () => switchTab(btn.dataset.tab));
  });

  // Play/Pause/Reset
  $('btn-play').addEventListener('click', togglePlay);
  $('btn-reset').addEventListener('click', resetSim);
  $('speed-slider').addEventListener('input', (e) => updateSpeed(e.target.value));

  // Pendulum params
  bindSlider('p-length', (v) => {
    sim.pendulum.length = v;
    $('p-length-val').textContent = v.toFixed(1) + ' m';
    resetSim();
  });
  bindSlider('p-gravity', (v) => {
    sim.pendulum.gravity = v;
    $('p-gravity-val').textContent = v.toFixed(1) + ' m/s\\u00B2';
    resetSim();
  });
  bindSlider('p-angle', (v) => {
    sim.pendulum.initialAngle = v;
    $('p-angle-val').textContent = v.toFixed(0) + '\\u00B0';
    resetSim();
  });

  // Projectile params
  bindSlider('pr-angle', (v) => {
    sim.projectile.angle = v;
    $('pr-angle-val').textContent = v.toFixed(0) + '\\u00B0';
    resetSim();
  });
  bindSlider('pr-velocity', (v) => {
    sim.projectile.velocity = v;
    $('pr-velocity-val').textContent = v.toFixed(0) + ' m/s';
    resetSim();
  });
  bindSlider('pr-gravity', (v) => {
    sim.projectile.gravity = v;
    $('pr-gravity-val').textContent = v.toFixed(1) + ' m/s\\u00B2';
    resetSim();
  });

  // Spring params
  bindSlider('s-k', (v) => {
    sim.spring.k = v;
    $('s-k-val').textContent = v.toFixed(0) + ' N/m';
    resetSim();
  });
  bindSlider('s-mass', (v) => {
    sim.spring.mass = v;
    $('s-mass-val').textContent = v.toFixed(1) + ' kg';
    resetSim();
  });
  bindSlider('s-disp', (v) => {
    sim.spring.initialDisp = v;
    $('s-disp-val').textContent = v.toFixed(1) + ' m';
    resetSim();
  });

  // Initial render
  resetSim();
};

document.addEventListener('DOMContentLoaded', init);
`

