export type Vec2 = { x: number; y: number }

export type PhysicsState = {
  position: Vec2
  velocity: Vec2
  acceleration: Vec2
  time: number
}

// --- Pendulum ---

export type PendulumParams = {
  length: number
  gravity: number
  damping: number
}

export type PendulumState = {
  angle: number
  angularVelocity: number
  angularAcceleration: number
  time: number
}

export const createPendulumState = (initialAngle: number): PendulumState => ({
  angle: initialAngle,
  angularVelocity: 0,
  angularAcceleration: 0,
  time: 0,
})

export const stepPendulum = (
  state: PendulumState,
  params: PendulumParams,
  dt: number,
): PendulumState => {
  const { angle, angularVelocity, time } = state
  const { length, gravity, damping } = params

  const angularAcceleration =
    (-gravity / length) * Math.sin(angle) - damping * angularVelocity

  const newAngularVelocity = angularVelocity + angularAcceleration * dt
  const newAngle = angle + newAngularVelocity * dt

  return {
    angle: newAngle,
    angularVelocity: newAngularVelocity,
    angularAcceleration,
    time: time + dt,
  }
}

export const pendulumToCartesian = (
  state: PendulumState,
  params: PendulumParams,
  origin: Vec2,
): Vec2 => ({
  x: origin.x + params.length * Math.sin(state.angle) * 100,
  y: origin.y + params.length * Math.cos(state.angle) * 100,
})

export const pendulumPhysics = (
  state: PendulumState,
  params: PendulumParams,
): PhysicsState => {
  const l = params.length
  const { angle, angularVelocity, angularAcceleration } = state
  return {
    position: {
      x: l * Math.sin(angle),
      y: -l * Math.cos(angle),
    },
    velocity: {
      x: l * angularVelocity * Math.cos(angle),
      y: l * angularVelocity * Math.sin(angle),
    },
    acceleration: {
      x:
        l * angularAcceleration * Math.cos(angle) -
        l * angularVelocity * angularVelocity * Math.sin(angle),
      y:
        l * angularAcceleration * Math.sin(angle) +
        l * angularVelocity * angularVelocity * Math.cos(angle),
    },
    time: state.time,
  }
}

// --- Projectile ---

export type ProjectileParams = {
  angle: number
  initialVelocity: number
  gravity: number
}

export type ProjectileState = {
  x: number
  y: number
  vx: number
  vy: number
  time: number
  landed: boolean
  trail: Vec2[]
}

export const createProjectileState = (params: ProjectileParams): ProjectileState => {
  const rad = (params.angle * Math.PI) / 180
  return {
    x: 0,
    y: 0,
    vx: params.initialVelocity * Math.cos(rad),
    vy: params.initialVelocity * Math.sin(rad),
    time: 0,
    landed: false,
    trail: [{ x: 0, y: 0 }],
  }
}

export const stepProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  dt: number,
): ProjectileState => {
  if (state.landed) return state

  const { x, y, vx, vy, time, trail } = state
  const { gravity } = params

  const newVy = vy - gravity * dt
  const newX = x + vx * dt
  const newY = y + newVy * dt

  const hasLanded = newY < 0 && time > 0

  const clampedY = hasLanded ? 0 : newY
  const clampedX = hasLanded ? x + vx * (y / (gravity * dt)) * dt * 0.5 : newX

  const newTrail = [...trail, { x: clampedX, y: clampedY }]

  return {
    x: clampedX,
    y: clampedY,
    vx: hasLanded ? 0 : vx,
    vy: hasLanded ? 0 : newVy,
    time: time + dt,
    landed: hasLanded,
    trail: newTrail,
  }
}

export const projectilePhysics = (
  state: ProjectileState,
  params: ProjectileParams,
): PhysicsState => ({
  position: { x: state.x, y: state.y },
  velocity: { x: state.vx, y: state.vy },
  acceleration: { x: 0, y: -params.gravity },
  time: state.time,
})

// --- Spring-Mass ---

export type SpringParams = {
  springConstant: number
  mass: number
  damping: number
}

export type SpringState = {
  displacement: number
  velocity: number
  acceleration: number
  time: number
}

export const createSpringState = (initialDisplacement: number): SpringState => ({
  displacement: initialDisplacement,
  velocity: 0,
  acceleration: 0,
  time: 0,
})

export const stepSpring = (
  state: SpringState,
  params: SpringParams,
  dt: number,
): SpringState => {
  const { displacement, velocity, time } = state
  const { springConstant, mass, damping } = params

  const acceleration = (-springConstant / mass) * displacement - (damping / mass) * velocity
  const newVelocity = velocity + acceleration * dt
  const newDisplacement = displacement + newVelocity * dt

  return {
    displacement: newDisplacement,
    velocity: newVelocity,
    acceleration,
    time: time + dt,
  }
}

export const springPhysics = (state: SpringState): PhysicsState => ({
  position: { x: state.displacement, y: 0 },
  velocity: { x: state.velocity, y: 0 },
  acceleration: { x: state.acceleration, y: 0 },
  time: state.time,
})

