export const renderPendulumSVG = (
  bobPos: Vec2,
  origin: Vec2,
  trail: Vec2[],
) => {
  const trailPath =
    trail.length > 1
      ? trail.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ')
      : ''

  return h('svg', {
      viewBox: '0 0 600 320',
      style: styleToStr(styles.svg),
    },
    // Background grid
    h('defs', {},
      h('pattern', { id: 'grid', width: '30', height: '30', patternUnits: 'userSpaceOnUse' },
        h('path', {
          d: 'M 30 0 L 0 0 0 30',
          fill: 'none',
          stroke: '#1a1a3e',
          'stroke-width': '0.5',
        }),
      ),
    ),
    h('rect', { width: '600', height: '320', fill: 'url(#grid)' }),
    // Pivot point
    h('circle', { cx: String(origin.x), cy: String(origin.y), r: '5', fill: '#8892b0' }),
    // Trail
    trailPath
      ? h('path', { d: trailPath, fill: 'none', stroke: '#64ffda', 'stroke-width': '1.5', opacity: '0.4' })
      : null,
    // Rod
    h('line', {
      x1: String(origin.x),
      y1: String(origin.y),
      x2: String(bobPos.x),
      y2: String(bobPos.y),
      stroke: '#8892b0',
      'stroke-width': '2',
    }),
    // Bob
    h('circle', {
      cx: String(bobPos.x),
      cy: String(bobPos.y),
      r: '14',
      fill: '#e94560',
      stroke: '#ff6b81',
      'stroke-width': '2',
    }),
    // Labels
    h('text', { x: '10', y: '20', fill: '#8892b0', 'font-size': '12', 'font-family': 'monospace' },
      'Simple Pendulum',
    ),
  )
}

export const renderProjectileSVG = (
  currentPos: Vec2,
  trail: Vec2[],
  maxRange: number,
  maxHeight: number,
) => {
  const padX = 50
  const padY = 40
  const w = 600 - padX * 2
  const drawH = 320 - padY * 2

  const scaleX = maxRange > 0 ? w / (maxRange * 1.1) : 1
  const scaleY = maxHeight > 0 ? drawH / (maxHeight * 1.2) : 1

  const toSVG = (p: Vec2): Vec2 => ({
    x: padX + p.x * scaleX,
    y: 320 - padY - p.y * scaleY,
  })

  const ground = 320 - padY

  const trailPath = trail
    .map((p, i) => {
      const sp = toSVG(p)
      return `${i === 0 ? 'M' : 'L'} ${sp.x} ${sp.y}`
    })
    .join(' ')

  const cur = toSVG(currentPos)

  return h('svg', {
      viewBox: '0 0 600 320',
      style: styleToStr(styles.svg),
    },
    h('defs', {},
      h('pattern', { id: 'grid2', width: '30', height: '30', patternUnits: 'userSpaceOnUse' },
        h('path', {
          d: 'M 30 0 L 0 0 0 30',
          fill: 'none',
          stroke: '#1a1a3e',
          'stroke-width': '0.5',
        }),
      ),
    ),
    h('rect', { width: '600', height: '320', fill: 'url(#grid2)' }),
    // Ground line
    h('line', {
      x1: String(padX),
      y1: String(ground),
      x2: String(600 - padX),
      y2: String(ground),
      stroke: '#3a3a5c',
      'stroke-width': '2',
    }),
    // Trajectory
    trailPath
      ? h('path', { d: trailPath, fill: 'none', stroke: '#64ffda', 'stroke-width': '2', opacity: '0.6' })
      : null,
    // Current position
    h('circle', {
      cx: String(cur.x),
      cy: String(cur.y),
      r: '8',
      fill: '#e94560',
      stroke: '#ff6b81',
      'stroke-width': '2',
    }),
    // Launcher
    h('rect', {
      x: String(padX - 5),
      y: String(ground - 10),
      width: '10',
      height: '10',
      fill: '#8892b0',
      rx: '2',
    }),
    // Label
    h('text', { x: '10', y: '20', fill: '#8892b0', 'font-size': '12', 'font-family': 'monospace' },
      'Projectile Motion',
    ),
  )
}

export const renderSpringSVG = (
  displacement: number,
  maxDisplacement: number,
) => {
  const centerX = 300
  const restY = 100
  const scale = 150 / Math.max(maxDisplacement, 0.5)
  const bobY = restY + displacement * scale

  // Generate spring coils path
  const coils = 8
  const amplitude = 15
  const springTop = 40
  const springLen = bobY - 20

  let springPath = `M ${centerX} ${springTop}`
  for (let i = 0; i <= coils * 2; i++) {
    const t = i / (coils * 2)
    const y = springTop + t * (springLen - springTop)
    const x = centerX + (i % 2 === 0 ? -amplitude : amplitude) * (i > 0 && i < coils * 2 ? 1 : 0)
    springPath += ` L ${x} ${y}`
  }
  springPath += ` L ${centerX} ${springLen}`

  // Equilibrium line
  const eqY = restY

  return h('svg', {
      viewBox: '0 0 600 320',
      style: styleToStr(styles.svg),
    },
    h('defs', {},
      h('pattern', { id: 'grid3', width: '30', height: '30', patternUnits: 'userSpaceOnUse' },
        h('path', {
          d: 'M 30 0 L 0 0 0 30',
          fill: 'none',
          stroke: '#1a1a3e',
          'stroke-width': '0.5',
        }),
      ),
    ),
    h('rect', { width: '600', height: '320', fill: 'url(#grid3)' }),
    // Wall
    h('rect', { x: '250', y: '20', width: '100', height: '20', fill: '#3a3a5c', rx: '3' }),
    h('line', { x1: '260', y1: '20', x2: '250', y2: '30', stroke: '#555', 'stroke-width': '1' }),
    h('line', { x1: '280', y1: '20', x2: '270', y2: '30', stroke: '#555', 'stroke-width': '1' }),
    h('line', { x1: '300', y1: '20', x2: '290', y2: '30', stroke: '#555', 'stroke-width': '1' }),
    h('line', { x1: '320', y1: '20', x2: '310', y2: '30', stroke: '#555', 'stroke-width': '1' }),
    h('line', { x1: '340', y1: '20', x2: '330', y2: '30', stroke: '#555', 'stroke-width': '1' }),
    // Equilibrium line (dashed)
    h('line', {
      x1: '200',
      y1: String(eqY),
      x2: '400',
      y2: String(eqY),
      stroke: '#64ffda',
      'stroke-width': '1',
      'stroke-dasharray': '5,5',
      opacity: '0.4',
    }),
    h('text', {
      x: '405',
      y: String(eqY + 4),
      fill: '#64ffda',
      'font-size': '10',
      'font-family': 'monospace',
      opacity: '0.6',
    }, 'equilibrium'),
    // Spring
    h('path', {
      d: springPath,
      fill: 'none',
      stroke: '#8892b0',
      'stroke-width': '2',
    }),
    // Mass block
    h('rect', {
      x: String(centerX - 20),
      y: String(bobY - 20),
      width: '40',
      height: '40',
      fill: '#e94560',
      stroke: '#ff6b81',
      'stroke-width': '2',
      rx: '4',
    }),
    h('text', {
      x: String(centerX),
      y: String(bobY + 5),
      fill: '#fff',
      'font-size': '12',
      'font-family': 'monospace',
      'text-anchor': 'middle',
    }, 'm'),
    // Displacement arrow
    displacement !== 0
      ? h('g', {},
          h('line', {
            x1: String(centerX + 40),
            y1: String(eqY),
            x2: String(centerX + 40),
            y2: String(bobY),
            stroke: '#ffa500',
            'stroke-width': '2',
            'marker-end': 'url(#arrow)',
          }),
          h('text', {
            x: String(centerX + 55),
            y: String((eqY + bobY) / 2 + 4),
            fill: '#ffa500',
            'font-size': '11',
            'font-family': 'monospace',
          }, `${fmt(displacement)}m`),
        )
      : null,
    // Label
    h('text', { x: '10', y: '20', fill: '#8892b0', 'font-size': '12', 'font-family': 'monospace' },
      'Spring-Mass System',
    ),
  )
}

