import { h, createSSR } from 'plaited'
import {
  type PendulumParams,
  type PendulumState,
  type ProjectileParams,
  type ProjectileState,
  type SpringParams,
  type SpringState,
  type Vec2,
  createPendulumState,
  createProjectileState,
  createSpringState,
  stepPendulum,
  stepProjectile,
  stepSpring,
  pendulumToCartesian,
  pendulumPhysics,
  projectilePhysics,
  springPhysics,
} from './physics'
import {
  renderPage,
  renderReadouts,
  renderSlider,
  renderPendulumSVG,
  renderProjectileSVG,
  renderSpringSVG,
} from './renderer'

// --- Types ---

type SimTab = 'pendulum' | 'projectile' | 'spring'

type SimState = {
  activeTab: SimTab
  playing: boolean
  speed: number

  pendulum: PendulumState
  pendulumParams: PendulumParams
  pendulumTrail: Vec2[]

  projectile: ProjectileState
  projectileParams: ProjectileParams

  spring: SpringState
  springParams: SpringParams
}

// --- Default state ---

const defaultPresets = async (): Promise<{
  pendulum: { length: number; gravity: number; initialAngle: number; damping: number }
  projectile: { angle: number; initialVelocity: number; gravity: number }
  spring: { springConstant: number; mass: number; initialDisplacement: number; damping: number }
}> => {
  try {
    const file = Bun.file('./data/presets.json')
    return await file.json()
  } catch {
    return {
      pendulum: { length: 1.5, gravity: 9.81, initialAngle: 0.785, damping: 0.001 },
      projectile: { angle: 45, initialVelocity: 20, gravity: 9.81 },
      spring: { springConstant: 10, mass: 1.0, initialDisplacement: 0.5, damping: 0.01 },
    }
  }
}

const createInitialState = async (): Promise<SimState> => {
  const presets = await defaultPresets()
  return {
    activeTab: 'pendulum',
    playing: false,
    speed: 1,
    pendulum: createPendulumState(presets.pendulum.initialAngle),
    pendulumParams: {
      length: presets.pendulum.length,
      gravity: presets.pendulum.gravity,
      damping: presets.pendulum.damping,
    },
    pendulumTrail: [],
    projectile: createProjectileState({
      angle: presets.projectile.angle,
      initialVelocity: presets.projectile.initialVelocity,
      gravity: presets.projectile.gravity,
    }),
    projectileParams: {
      angle: presets.projectile.angle,
      initialVelocity: presets.projectile.initialVelocity,
      gravity: presets.projectile.gravity,
    },
    spring: createSpringState(presets.spring.initialDisplacement),
    springParams: {
      springConstant: presets.spring.springConstant,
      mass: presets.spring.mass,
      damping: presets.spring.damping,
    },
  }
}

// --- Simulation step ---

const FIXED_DT = 1 / 60
const PENDULUM_ORIGIN: Vec2 = { x: 300, y: 40 }
const MAX_TRAIL_LENGTH = 200

const tick = (state: SimState): SimState => {
  if (!state.playing) return state

  const dt = FIXED_DT * state.speed

  switch (state.activeTab) {
    case 'pendulum': {
      const newPendulum = stepPendulum(state.pendulum, state.pendulumParams, dt)
      const bobPos = pendulumToCartesian(newPendulum, state.pendulumParams, PENDULUM_ORIGIN)
      const trail = [...state.pendulumTrail, bobPos].slice(-MAX_TRAIL_LENGTH)
      return { ...state, pendulum: newPendulum, pendulumTrail: trail }
    }
    case 'projectile': {
      const newProjectile = stepProjectile(state.projectile, state.projectileParams, dt)
      return { ...state, projectile: newProjectile }
    }
    case 'spring': {
      const newSpring = stepSpring(state.spring, state.springParams, dt)
      return { ...state, spring: newSpring }
    }
  }
}

// --- Event handling ---

type SimEvent =
  | { type: 'tab-pendulum' }
  | { type: 'tab-projectile' }
  | { type: 'tab-spring' }
  | { type: 'toggle-play' }
  | { type: 'reset' }
  | { type: 'speed-change'; value: number }
  | { type: 'pendulum-length'; value: number }
  | { type: 'pendulum-gravity'; value: number }
  | { type: 'projectile-angle'; value: number }
  | { type: 'projectile-velocity'; value: number }
  | { type: 'spring-constant'; value: number }
  | { type: 'spring-mass'; value: number }

const handleEvent = (state: SimState, event: SimEvent): SimState => {
  switch (event.type) {
    case 'tab-pendulum':
      return { ...state, activeTab: 'pendulum' }
    case 'tab-projectile':
      return { ...state, activeTab: 'projectile' }
    case 'tab-spring':
      return { ...state, activeTab: 'spring' }
    case 'toggle-play':
      return { ...state, playing: !state.playing }
    case 'reset': {
      const resetState = { ...state, playing: false }
      switch (state.activeTab) {
        case 'pendulum':
          return {
            ...resetState,
            pendulum: createPendulumState(0.785),
            pendulumTrail: [],
          }
        case 'projectile':
          return {
            ...resetState,
            projectile: createProjectileState(state.projectileParams),
          }
        case 'spring':
          return {
            ...resetState,
            spring: createSpringState(0.5),
          }
      }
      return resetState
    }
    case 'speed-change':
      return { ...state, speed: event.value }
    case 'pendulum-length':
      return {
        ...state,
        pendulumParams: { ...state.pendulumParams, length: event.value },
      }
    case 'pendulum-gravity':
      return {
        ...state,
        pendulumParams: { ...state.pendulumParams, gravity: event.value },
      }
    case 'projectile-angle':
      return {
        ...state,
        projectileParams: { ...state.projectileParams, angle: event.value },
        projectile: createProjectileState({
          ...state.projectileParams,
          angle: event.value,
        }),
      }
    case 'projectile-velocity':
      return {
        ...state,
        projectileParams: { ...state.projectileParams, initialVelocity: event.value },
        projectile: createProjectileState({
          ...state.projectileParams,
          initialVelocity: event.value,
        }),
      }
    case 'spring-constant':
      return {
        ...state,
        springParams: { ...state.springParams, springConstant: event.value },
      }
    case 'spring-mass':
      return {
        ...state,
        springParams: { ...state.springParams, mass: event.value },
      }
  }
}

// --- Render function ---

const render = (state: SimState): string => {
  const { activeTab, playing, speed } = state

  let svgContent: ReturnType<typeof h>
  let readouts: ReturnType<typeof h>
  let sliders: ReturnType<typeof h>

  switch (activeTab) {
    case 'pendulum': {
      const physics = pendulumPhysics(state.pendulum, state.pendulumParams)
      const bobPos = pendulumToCartesian(state.pendulum, state.pendulumParams, PENDULUM_ORIGIN)
      svgContent = renderPendulumSVG(bobPos, PENDULUM_ORIGIN, state.pendulumTrail)
      readouts = renderReadouts(physics)
      sliders = h('fragment', {},
        renderSlider('Length', state.pendulumParams.length, 0.5, 3.0, 0.1, 'm', 'pendulum-length'),
        renderSlider('Gravity', state.pendulumParams.gravity, 1, 20, 0.1, 'm/s²', 'pendulum-gravity'),
      )
      break
    }
    case 'projectile': {
      const physics = projectilePhysics(state.projectile, state.projectileParams)
      const { angle, initialVelocity, gravity } = state.projectileParams
      const rad = (angle * Math.PI) / 180
      const maxRange = (initialVelocity * initialVelocity * Math.sin(2 * rad)) / gravity
      const maxHeight = (initialVelocity * initialVelocity * Math.sin(rad) ** 2) / (2 * gravity)
      svgContent = renderProjectileSVG(
        { x: state.projectile.x, y: state.projectile.y },
        state.projectile.trail,
        maxRange,
        maxHeight,
      )
      readouts = renderReadouts(physics)
      sliders = h('fragment', {},
        renderSlider('Angle', state.projectileParams.angle, 5, 85, 1, '°', 'projectile-angle'),
        renderSlider('Initial Velocity', state.projectileParams.initialVelocity, 5, 50, 1, 'm/s', 'projectile-velocity'),
      )
      break
    }
    case 'spring': {
      const physics = springPhysics(state.spring)
      svgContent = renderSpringSVG(state.spring.displacement, 0.5)
      readouts = renderReadouts(physics)
      sliders = h('fragment', {},
        renderSlider('Spring Constant (k)', state.springParams.springConstant, 1, 50, 0.5, 'N/m', 'spring-constant'),
        renderSlider('Mass', state.springParams.mass, 0.1, 5.0, 0.1, 'kg', 'spring-mass'),
      )
      break
    }
  }

  const time =
    activeTab === 'pendulum'
      ? state.pendulum.time
      : activeTab === 'projectile'
        ? state.projectile.time
        : state.spring.time

  const page = renderPage(activeTab, playing, speed, time, svgContent, readouts, sliders)
  const ssr = createSSR()
  return ssr(page)
}

// --- Server ---

const serve = async () => {
  let state = await createInitialState()

  const server = Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/') {
        const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Newton's Laws Simulator</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #0a0a1a; min-height: 100vh; display: flex; justify-content: center; padding: 20px; }
    input[type="range"] { height: 6px; border-radius: 3px; }
  </style>
</head>
<body>
  <div id="app">${render(state)}</div>
  <script>
    const FPS = 60;
    let interval = null;

    const sendEvent = async (type, value) => {
      const res = await fetch('/event', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ type, value }),
      });
      const html = await res.text();
      document.getElementById('app').innerHTML = html;
      rebind();
    };

    const tickLoop = async () => {
      const res = await fetch('/tick', { method: 'POST' });
      const data = await res.json();
      if (data.html) {
        document.getElementById('app').innerHTML = data.html;
        rebind();
      }
      if (!data.playing && interval) {
        clearInterval(interval);
        interval = null;
      }
    };

    const rebind = () => {
      document.querySelectorAll('[p-trigger]').forEach(el => {
        const trigger = el.getAttribute('p-trigger');
        if (el.tagName === 'INPUT') {
          el.oninput = (e) => sendEvent(trigger, parseFloat(e.target.value));
        } else {
          el.onclick = () => {
            sendEvent(trigger);
            if (trigger === 'toggle-play') {
              if (!interval) {
                interval = setInterval(tickLoop, 1000 / FPS);
              }
            }
            if (trigger === 'reset' && interval) {
              clearInterval(interval);
              interval = null;
            }
          };
        }
      });
    };

    rebind();
  </script>
</body>
</html>`;
        return new Response(html, { headers: { 'Content-Type': 'text/html' } })
      }

      if (url.pathname === '/event' && req.method === 'POST') {
        const body = await req.json() as { type: string; value?: number }
        state = handleEvent(state, body as SimEvent)
        return new Response(render(state), { headers: { 'Content-Type': 'text/html' } })
      }

      if (url.pathname === '/tick' && req.method === 'POST') {
        state = tick(state)
        return Response.json({
          html: render(state),
          playing: state.playing,
        })
      }

      if (url.pathname === '/state') {
        const activeState =
          state.activeTab === 'pendulum'
            ? pendulumPhysics(state.pendulum, state.pendulumParams)
            : state.activeTab === 'projectile'
              ? projectilePhysics(state.projectile, state.projectileParams)
              : springPhysics(state.spring)
        return Response.json(activeState)
      }

      return new Response('Not Found', { status: 404 })
    },
  })

  console.log(`Newton's Laws Simulator running at http://localhost:${server.port}`)
}

// --- Exports ---

export {
  type SimState,
  type SimEvent,
  type SimTab,
  createInitialState,
  tick,
  handleEvent,
  render,
  serve,
}

// Run server if executed directly
serve()

