286→    html += '<line x1="' + massX.toFixed(1) + '" y1="' + (cy-40) + '" x2="' + (massX + force*fs).toFixed(1) + '" y2="' + (cy-40) + '" stroke="#f59e0b" stroke-width="2.5" marker-end="url(#arrowYellow)"/>';
287→    html += '<text x="' + (massX + force*fs/2).toFixed(1) + '" y="' + (cy-48) + '" fill="#f59e0b" font-size="10" text-anchor="middle">F</text>';
288→  }
289→  // Displacement indicator
290→  if (Math.abs(s.disp) > 0.01) {
291→    html += '<line x1="' + eqX + '" y1="' + (cy+70) + '" x2="' + massX.toFixed(1) + '" y2="' + (cy+70) + '" stroke="#a78bfa" stroke-width="1.5" marker-end="url(#arrowPurple)"/>';
292→    html += '<text x="' + ((eqX+massX)/2).toFixed(1) + '" y="' + (cy+85) + '" fill="#a78bfa" font-size="10" text-anchor="middle">' + s.disp.toFixed(2) + ' m</text>';
293→  }
294→  // Displacement-time graph (mini)
295→  if (s.trail.length > 2) {
296→    const gx = 350, gy = 80, gw = 220, gh = 60;
297→    html += '<rect x="' + gx + '" y="' + (gy-gh/2) + '" width="' + gw + '" height="' + gh + '" fill="rgba(15,23,42,0.6)" rx="4" stroke="#334155" stroke-width="1"/>';
298→    html += '<line x1="' + gx + '" y1="' + gy + '" x2="' + (gx+gw) + '" y2="' + gy + '" stroke="#334155" stroke-width="0.5"/>';
299→    html += '<text x="' + (gx+gw/2) + '" y="' + (gy-gh/2-4) + '" fill="#94a3b8" font-size="9" text-anchor="middle">displacement vs time</text>';
300→    const tMin = s.trail[0].t, tMax = s.trail[s.trail.length-1].t;
301→    const tRange = Math.max(tMax - tMin, 0.1);
302→    let maxD = 0;
303→    for (const pt of s.trail) { if (Math.abs(pt.x) > maxD) maxD = Math.abs(pt.x); }
304→    maxD = Math.max(maxD, 0.1);
305→    let pts = '';
306→    for (const pt of s.trail) {
307→      const px = gx + ((pt.t - tMin) / tRange) * gw;
308→      const py = gy - (pt.x / maxD) * (gh/2 - 4);
309→      pts += px.toFixed(1) + ',' + py.toFixed(1) + ' ';
310→    }
311→    html += '<polyline points="' + pts + '" fill="none" stroke="#a78bfa" stroke-width="1.5"/>';
312→  }
313→  svg.innerHTML = html;
314→
315→  // Values
316→  const acc = -(s.k / s.mass) * s.disp;
317→  $('val-pos').textContent = 'displacement: ' + s.disp.toFixed(3) + ' m';
318→  $('val-vel').textContent = s.vel.toFixed(3) + ' m/s';
319→  $('val-acc').textContent = acc.toFixed(3) + ' m/s\\u00B2';
320→  $('val-time').textContent = sim.time.toFixed(2) + ' s';
321→  const omega = Math.sqrt(s.k / s.mass);
322→  const period = 2 * Math.PI / omega;
323→  $('val-extra').textContent = 'Period: ' + period.toFixed(3) + ' s, \\u03C9: ' + omega.toFixed(3) + ' rad/s, F: ' + (s.k * s.disp).toFixed(2) + ' N';
324→};
325→
326→// ── Animation Loop ───────────────────────────────────────────────────────
327→const DT = 1 / 120;
328→
329→const animate = (timestamp) => {
330→  if (!sim.running) return;
331→  if (!sim.lastFrame) sim.lastFrame = timestamp;
332→  const elapsed = Math.min((timestamp - sim.lastFrame) / 1000, 0.05);
333→  sim.lastFrame = timestamp;
334→
335→  const steps = Math.max(1, Math.round(elapsed / DT * sim.speed));
336→  const actualDt = DT;
337→
338→  for (let i = 0; i < steps; i++) {
339→    sim.time += actualDt;
340→    if (sim.active === 'pendulum') stepPendulum(actualDt);
341→    else if (sim.active === 'projectile') stepProjectile(actualDt);
342→    else if (sim.active === 'spring') stepSpring(actualDt);
343→  }
344→
345→  if (sim.active === 'pendulum') renderPendulum();
346→  else if (sim.active === 'projectile') renderProjectile();
347→  else if (sim.active === 'spring') renderSpring();
348→
349→  sim.animId = requestAnimationFrame(animate);
350→};
351→
352→// ── Controls ─────────────────────────────────────────────────────────────
353→const play = () => {
354→  if (sim.active === 'projectile' && !sim.projectile.launched) {
355→    sim.projectile.launched = false;
356→  }
357→  sim.running = true;
358→  sim.lastFrame = 0;
359→  sim.animId = requestAnimationFrame(animate);
360→  $('btn-play').textContent = 'Pause';
361→};
362→
363→const pause = () => {
364→  sim.running = false;
365→  if (sim.animId) cancelAnimationFrame(sim.animId);
366→  $('btn-play').textContent = 'Play';
367→};
368→
369→const togglePlay = () => {
370→  if (sim.running) pause(); else play();
371→};
372→
373→const resetSim = () => {
374→  pause();
375→  sim.time = 0;
376→  if (sim.active === 'pendulum') {
377→    const p = sim.pendulum;
378→    p.theta = p.initialAngle * Math.PI / 180;
379→    p.omega = 0;
380→    p.trail = [];
381→  } else if (sim.active === 'projectile') {
382→    const p = sim.projectile;
383→    p.x = 0; p.y = 0; p.vx = 0; p.vy = 0;
384→    p.trajectory = [];
385→    p.launched = false;
386→    p.landed = false;
387→  } else if (sim.active === 'spring') {
388→    const s = sim.spring;
389→    s.disp = s.initialDisp;
390→    s.vel = 0;
391→    s.trail = [];
392→  }
393→  renderActive();
394→};
395→
396→const renderActive = () => {
397→  if (sim.active === 'pendulum') renderPendulum();
398→  else if (sim.active === 'projectile') renderProjectile();
399→  else if (sim.active === 'spring') renderSpring();
400→};
401→
402→const switchTab = (tab) => {
403→  pause();
404→  sim.active = tab;
405→  sim.time = 0;
406→  document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
407→  document.querySelector('[data-tab="' + tab + '"]').classList.add('active');
408→  // Show/hide param panels
409→  document.querySelectorAll('.param-panel').forEach(p => p.style.display = 'none');
410→  $('params-' + tab).style.display = 'flex';
411→  resetSim();
412→};
413→
414→const updateSpeed = (val) => {
415→  sim.speed = parseFloat(val);
416→  $('speed-label').textContent = sim.speed.toFixed(2) + 'x';
417→};
418→
419→// ── Parameter Handlers ───────────────────────────────────────────────────
420→const bindSlider = (id, callback) => {
421→  const el = $(id);
422→  if (!el) return;
423→  el.addEventListener('input', (e) => {
424→    callback(parseFloat(e.target.value));
425→    if (!sim.running) renderActive();
426→  });
427→};
428→
429→const init = () => {
430→  // Tab buttons
431→  document.querySelectorAll('.tab-btn').forEach(btn => {
432→    btn.addEventListener('click', () => switchTab(btn.dataset.tab));
433→  });
434→
435→  // Play/Pause/Reset
436→  $('btn-play').addEventListener('click', togglePlay);
437→  $('btn-reset').addEventListener('click', resetSim);
438→  $('speed-slider').addEventListener('input', (e) => updateSpeed(e.target.value));
439→
440→  // Pendulum params
441→  bindSlider('p-length', (v) => {
442→    sim.pendulum.length = v;
443→    $('p-length-val').textContent = v.toFixed(1) + ' m';
444→    resetSim();
445→  });
446→  bindSlider('p-gravity', (v) => {
447→    sim.pendulum.gravity = v;
448→    $('p-gravity-val').textContent = v.toFixed(1) + ' m/s\\u00B2';
449→    resetSim();
450→  });
451→  bindSlider('p-angle', (v) => {
452→    sim.pendulum.initialAngle = v;
453→    $('p-angle-val').textContent = v.toFixed(0) + '\\u00B0';
454→    resetSim();
455→  });
456→
457→  // Projectile params
458→  bindSlider('pr-angle', (v) => {
459→    sim.projectile.angle = v;
460→    $('pr-angle-val').textContent = v.toFixed(0) + '\\u00B0';
461→    resetSim();
462→  });
463→  bindSlider('pr-velocity', (v) => {
464→    sim.projectile.velocity = v;
465→    $('pr-velocity-val').textContent = v.toFixed(0) + ' m/s';
466→    resetSim();
467→  });
468→  bindSlider('pr-gravity', (v) => {
469→    sim.projectile.gravity = v;
470→    $('pr-gravity-val').textContent = v.toFixed(1) + ' m/s\\u00B2';
471→    resetSim();
472→  });
473→
474→  // Spring params
475→  bindSlider('s-k', (v) => {
476→    sim.spring.k = v;
477→    $('s-k-val').textContent = v.toFixed(0) + ' N/m';
478→    resetSim();
479→  });
480→  bindSlider('s-mass', (v) => {
481→    sim.spring.mass = v;
482→    $('s-mass-val').textContent = v.toFixed(1) + ' kg';
483→    resetSim();
484→  });
485→  bindSlider('s-disp', (v) => {
486→    sim.spring.initialDisp = v;
487→    $('s-disp-val').textContent = v.toFixed(1) + ' m';
488→    resetSim();
489→  });
490→
491→  // Initial render
492→  resetSim();
493→};
494→
495→document.addEventListener('DOMContentLoaded', init);
