{
  "name": "@node/newton-sim",
  "version": "1.0.0",
  "description": "Interactive Newton's laws simulator with pendulum, projectile motion, and spring-mass systems",
  "main": "index.ts",
  "modnet": {
    "contentType": "science",
    "structure": "steps",
    "mechanics": ["track", "chart"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type Vec2 = {
  x: number
  y: number
}

export type SimulationType = 'pendulum' | 'projectile' | 'spring'

export type PendulumParams = {
  length: number
  gravity: number
  initialAngle: number
  damping: number
}

export type ProjectileParams = {
  angle: number
  initialVelocity: number
  gravity: number
}

export type SpringParams = {
  springConstant: number
  mass: number
  initialDisplacement: number
  damping: number
}

export type PhysicsReadout = {
  position: Vec2
  velocity: Vec2
  acceleration: Vec2
  time: number
}

export type SimulationState = {
  type: SimulationType
  speed: number
  running: boolean
  time: number
}

export type PendulumState = {
  theta: number
  omega: number
}

export type ProjectileState = {
  x: number
  y: number
  vx: number
  vy: number
  landed: boolean
  trail: Vec2[]
}

export type SpringState = {
  displacement: number
  velocity: number
}

export type Preset = {
  [key: string]: Record<string, number>
}

export type PresetsData = {
  pendulum: Record<string, PendulumParams>
  projectile: Record<string, ProjectileParams>
  spring: Record<string, SpringParams>
}

import type { PendulumParams, ProjectileParams, SpringParams, PhysicsReadout, Vec2 } from './types'

// 4th-order Runge-Kutta integrator for [position, velocity] state
export const rk4Step = (
  derivativeFn: (state: [number, number], t: number) => [number, number],
  state: [number, number],
  t: number,
  dt: number
): [number, number] => {
  const k1 = derivativeFn(state, t)
  const k2 = derivativeFn(
    [state[0] + k1[0] * dt / 2, state[1] + k1[1] * dt / 2],
    t + dt / 2
  )
  const k3 = derivativeFn(
    [state[0] + k2[0] * dt / 2, state[1] + k2[1] * dt / 2],
    t + dt / 2
  )
  const k4 = derivativeFn(
    [state[0] + k3[0] * dt, state[1] + k3[1] * dt],
    t + dt
  )
  return [
    state[0] + (dt / 6) * (k1[0] + 2 * k2[0] + 2 * k3[0] + k4[0]),
    state[1] + (dt / 6) * (k1[1] + 2 * k2[1] + 2 * k3[1] + k4[1]),
  ]
}

// Pendulum: theta'' = -(g/L)*sin(theta) - b*omega
export const pendulumDerivative = (params: PendulumParams) =>
  (state: [number, number], _t: number): [number, number] => {
    const [theta, omega] = state
    const alpha = -(params.gravity / params.length) * Math.sin(theta) - params.damping * omega
    return [omega, alpha]
  }

export const stepPendulum = (
  theta: number,
  omega: number,
  params: PendulumParams,
  dt: number,
  t: number
): { theta: number; omega: number; acceleration: number } => {
  const deriv = pendulumDerivative(params)
  const [newTheta, newOmega] = rk4Step(deriv, [theta, omega], t, dt)
  const acceleration = -(params.gravity / params.length) * Math.sin(newTheta) - params.damping * newOmega
  return { theta: newTheta, omega: newOmega, acceleration }
}

export const pendulumPosition = (theta: number, length: number): Vec2 => ({
  x: length * Math.sin(theta),
  y: length * Math.cos(theta),
})

export const pendulumReadout = (
  theta: number,
  omega: number,
  params: PendulumParams,
  time: number
): PhysicsReadout => {
  const pos = pendulumPosition(theta, params.length)
  const acceleration = -(params.gravity / params.length) * Math.sin(theta) - params.damping * omega
  return {
    position: pos,
    velocity: {
      x: params.length * omega * Math.cos(theta),
      y: -params.length * omega * Math.sin(theta),
    },
    acceleration: {
      x: params.length * (acceleration * Math.cos(theta) - omega * omega * Math.sin(theta)),
      y: -params.length * (acceleration * Math.sin(theta) + omega * omega * Math.cos(theta)),
    },
    time,
  }
}

// Projectile: simple Euler (no oscillation)
export const stepProjectile = (
  x: number,
  y: number,
  vx: number,
  vy: number,
  gravity: number,
  dt: number
): { x: number; y: number; vx: number; vy: number } => ({
  x: x + vx * dt,
  y: y + vy * dt - 0.5 * gravity * dt * dt,
  vx,
  vy: vy - gravity * dt,
})

export const projectileReadout = (
  x: number,
  y: number,
  vx: number,
  vy: number,
  gravity: number,
  time: number
): PhysicsReadout => ({
  position: { x, y },
  velocity: { x: vx, y: vy },
  acceleration: { x: 0, y: -gravity },
  time,
})

// Spring-mass: x'' = -(k/m)*x - (b/m)*v
export const springDerivative = (params: SpringParams) =>
  (state: [number, number], _t: number): [number, number] => {
    const [x, v] = state
    const a = -(params.springConstant / params.mass) * x - (params.damping / params.mass) * v
    return [v, a]
  }

export const stepSpring = (
  displacement: number,
  velocity: number,
  params: SpringParams,
  dt: number,
  t: number
): { displacement: number; velocity: number; acceleration: number } => {
  const deriv = springDerivative(params)
  const [newDisp, newVel] = rk4Step(deriv, [displacement, velocity], t, dt)
  const acceleration = -(params.springConstant / params.mass) * newDisp - (params.damping / params.mass) * newVel
  return { displacement: newDisp, velocity: newVel, acceleration }
}

export const springReadout = (
  displacement: number,
  velocity: number,
  params: SpringParams,
  time: number
): PhysicsReadout => {
  const acceleration = -(params.springConstant / params.mass) * displacement - (params.damping / params.mass) * velocity
  return {
    position: { x: displacement, y: 0 },
    velocity: { x: velocity, y: 0 },
    acceleration: { x: acceleration, y: 0 },
    time,
  }
}

