// Client-side simulation script — exported as a string to embed in <script> tag
export const clientScript = `
(function() {
  // === RK4 Integrator ===
  var rk4 = function(f, s, t, dt) {
    var k1 = f(s, t);
    var k2 = f([s[0]+k1[0]*dt/2, s[1]+k1[1]*dt/2], t+dt/2);
    var k3 = f([s[0]+k2[0]*dt/2, s[1]+k2[1]*dt/2], t+dt/2);
    var k4 = f([s[0]+k3[0]*dt, s[1]+k3[1]*dt], t+dt);
    return [
      s[0] + (dt/6)*(k1[0]+2*k2[0]+2*k3[0]+k4[0]),
      s[1] + (dt/6)*(k1[1]+2*k2[1]+2*k3[1]+k4[1])
    ];
  };

  // === State ===
  var activeTab = 'pendulum';
  var running = false;
  var speed = 1.0;
  var time = 0;
  var lastFrame = null;
  var animId = null;

  // Pendulum state
  var pend = { theta: 0, omega: 0, trail: [] };
  var pendParams = { length: 2, gravity: 9.81, initialAngle: 45, damping: 0.02 };

  // Projectile state
  var proj = { x: 0, y: 0, vx: 0, vy: 0, landed: false, trail: [] };
  var projParams = { angle: 45, initialVelocity: 20, gravity: 9.81 };

  // Spring state
  var spr = { disp: 0, vel: 0, history: [] };
  var sprParams = { springConstant: 15, mass: 2, initialDisplacement: 1.5, damping: 0.1 };

  // === SVG Setup ===
  var W = 600, H = 400;
  var svg = document.getElementById('sim-canvas');

  // === Helpers ===
  var rad = function(d) { return d * Math.PI / 180; };
  var deg = function(r) { return r * 180 / Math.PI; };
  var fmt = function(v) { return (v >= 0 ? ' ' : '') + v.toFixed(3); };
  var mag = function(x, y) { return Math.sqrt(x*x + y*y); };

  // === Init functions ===
  var initPendulum = function() {
    pend.theta = rad(pendParams.initialAngle);
    pend.omega = 0;
    pend.trail = [];
    time = 0;
  };

  var initProjectile = function() {
    var a = rad(projParams.angle);
    proj.x = 0;
    proj.y = 0;
    proj.vx = projParams.initialVelocity * Math.cos(a);
    proj.vy = projParams.initialVelocity * Math.sin(a);
    proj.landed = false;
    proj.trail = [];
    time = 0;
  };

  var initSpring = function() {
    spr.disp = sprParams.initialDisplacement;
    spr.vel = 0;
    spr.history = [];
    time = 0;
  };

  var resetCurrent = function() {
    if (activeTab === 'pendulum') initPendulum();
    else if (activeTab === 'projectile') initProjectile();
    else initSpring();
    running = false;
    lastFrame = null;
    updatePlayBtn();
    render();
    updateReadout();
  };

  // === Physics step ===
  var DT = 1/120;

  var stepPhysics = function(dt) {
    if (activeTab === 'pendulum') {
      var pDeriv = function(s) {
        return [s[1], -(pendParams.gravity/pendParams.length)*Math.sin(s[0]) - pendParams.damping*s[1]];
      };
      var ns = rk4(pDeriv, [pend.theta, pend.omega], time, dt);
      pend.theta = ns[0];
      pend.omega = ns[1];
      // Store trail (bob position in SVG coords)
      var bx = 300 + pendParams.length * 80 * Math.sin(pend.theta);
      var by = 60 + pendParams.length * 80 * Math.cos(pend.theta);
      pend.trail.push([bx, by]);
      if (pend.trail.length > 200) pend.trail.shift();
    }
    else if (activeTab === 'projectile') {
      if (!proj.landed) {
        proj.x += proj.vx * dt;
        proj.y += proj.vy * dt - 0.5 * projParams.gravity * dt * dt;
        proj.vy -= projParams.gravity * dt;
        if (proj.y <= 0 && time > 0.01) {
          proj.y = 0;
          proj.landed = true;
        }
        proj.trail.push([proj.x, proj.y]);
        if (proj.trail.length > 2000) proj.trail.shift();
      }
    }
    else {
      var sDeriv = function(s) {
        return [s[1], -(sprParams.springConstant/sprParams.mass)*s[0] - (sprParams.damping/sprParams.mass)*s[1]];
      };
      var ns2 = rk4(sDeriv, [spr.disp, spr.vel], time, dt);
      spr.disp = ns2[0];
      spr.vel = ns2[1];
      spr.history.push([time, spr.disp]);
      if (spr.history.length > 400) spr.history.shift();
    }
    time += dt;
  };

  // === Rendering ===
  var renderPendulum = function() {
    var L = pendParams.length * 80;
    var pivotX = 300, pivotY = 60;
    var bobX = pivotX + L * Math.sin(pend.theta);
    var bobY = pivotY + L * Math.cos(pend.theta);
    var bobR = 14;

    var s = '';
    // Background grid
    s += '<rect width="600" height="400" fill="#0f172a"/>';
    for (var gy = 0; gy < 400; gy += 40) {
      s += '<line x1="0" y1="'+gy+'" x2="600" y2="'+gy+'" stroke="#1e293b" stroke-width="0.5"/>';
    }
    for (var gx = 0; gx < 600; gx += 40) {
      s += '<line x1="'+gx+'" y1="0" x2="'+gx+'" y2="400" stroke="#1e293b" stroke-width="0.5"/>';
    }

    // Pivot mount
    s += '<line x1="250" y1="'+pivotY+'" x2="350" y2="'+pivotY+'" stroke="#475569" stroke-width="3"/>';
    for (var hx = 255; hx < 350; hx += 10) {
      s += '<line x1="'+hx+'" y1="'+pivotY+'" x2="'+(hx-5)+'" y2="'+(pivotY-8)+'" stroke="#475569" stroke-width="1.5"/>';
    }

    // Trail
    if (pend.trail.length > 1) {
      s += '<polyline points="';
      for (var ti = 0; ti < pend.trail.length; ti++) {
        s += pend.trail[ti][0]+','+pend.trail[ti][1]+' ';
      }
      s += '" fill="none" stroke="#3b82f6" stroke-width="1.5" opacity="0.4"/>';
    }

    // Rod
    s += '<line x1="'+pivotX+'" y1="'+pivotY+'" x2="'+bobX+'" y2="'+bobY+'" stroke="#94a3b8" stroke-width="2.5"/>';

    // Angle arc
    var arcR = 40;
    if (Math.abs(pend.theta) > 0.02) {
      var startAngle = Math.PI/2; // straight down in SVG
      var endAngle = Math.PI/2 - pend.theta;
      var arcStartX = pivotX + arcR * Math.cos(startAngle);
      var arcStartY = pivotY + arcR * Math.sin(startAngle);
      var arcEndX = pivotX + arcR * Math.cos(endAngle);
      var arcEndY = pivotY + arcR * Math.sin(endAngle);
      var sweep = pend.theta > 0 ? 0 : 1;
      var largeArc = Math.abs(pend.theta) > Math.PI ? 1 : 0;
      s += '<path d="M'+arcStartX+','+arcStartY+' A'+arcR+','+arcR+' 0 '+largeArc+' '+sweep+' '+arcEndX+','+arcEndY+'" fill="none" stroke="#fbbf24" stroke-width="1.5" stroke-dasharray="4,3"/>';
      var labelAngle = (startAngle + endAngle) / 2;
      var labelX = pivotX + (arcR + 14) * Math.cos(labelAngle);
      var labelY = pivotY + (arcR + 14) * Math.sin(labelAngle);
      s += '<text x="'+labelX+'" y="'+labelY+'" fill="#fbbf24" font-size="12" text-anchor="middle">'+Math.abs(deg(pend.theta)).toFixed(1)+'\\u00B0</text>';
    }

    // Pivot dot
    s += '<circle cx="'+pivotX+'" cy="'+pivotY+'" r="5" fill="#64748b"/>';

    // Bob with gradient
    s += '<defs><radialGradient id="bobGrad"><stop offset="20%" stop-color="#60a5fa"/><stop offset="100%" stop-color="#2563eb"/></radialGradient></defs>';
    s += '<circle cx="'+bobX+'" cy="'+bobY+'" r="'+bobR+'" fill="url(#bobGrad)" stroke="#93c5fd" stroke-width="1.5"/>';

    // Velocity vector
    var vScale = 15;
    var vx = pendParams.length * pend.omega * Math.cos(pend.theta) * vScale;
    var vy = -pendParams.length * pend.omega * Math.sin(pend.theta) * vScale;
    if (Math.abs(vx) > 1 || Math.abs(vy) > 1) {
      s += '<line x1="'+bobX+'" y1="'+bobY+'" x2="'+(bobX+vx)+'" y2="'+(bobY+vy)+'" stroke="#22c55e" stroke-width="2.5" marker-end="url(#arrowGreen)"/>';
    }

    // Gravity vector
    s += '<line x1="'+bobX+'" y1="'+(bobY+bobR+4)+'" x2="'+bobX+'" y2="'+(bobY+bobR+30)+'" stroke="#f59e0b" stroke-width="2" marker-end="url(#arrowOrange)"/>';
    s += '<text x="'+(bobX+10)+'" y="'+(bobY+bobR+25)+'" fill="#f59e0b" font-size="10">g</text>';

    // Labels
    s += '<text x="15" y="25" fill="#94a3b8" font-size="13" font-weight="600">Simple Pendulum</text>';
    s += '<text x="15" y="385" fill="#64748b" font-size="11">L = '+pendParams.length.toFixed(1)+' m  |  g = '+pendParams.gravity.toFixed(1)+' m/s\\u00B2</text>';

    svg.innerHTML = s;
  };

  var renderProjectile = function() {
    var s = '';
    s += '<rect width="600" height="400" fill="#0f172a"/>';

    // Calculate scale
    var v0 = projParams.initialVelocity;
    var a = rad(projParams.angle);
    var g = projParams.gravity;
    var maxRange = (v0*v0*Math.sin(2*a))/g;
    var maxH = (v0*v0*Math.sin(a)*Math.sin(a))/(2*g);
    var scaleX = 520 / Math.max(maxRange, 1);
    var scaleY = 300 / Math.max(maxH * 1.3, 1);
    var scale = Math.min(scaleX, scaleY);
    var groundY = 360;
    var originX = 40;

    // Grid
    var gridSpacingM = Math.pow(10, Math.floor(Math.log10(maxRange/4)));
    if (gridSpacingM < 1) gridSpacingM = 1;
    for (var gm = 0; gm <= maxRange * 1.2; gm += gridSpacingM) {
      var gxp = originX + gm * scale;
      if (gxp > 580) break;
      s += '<line x1="'+gxp+'" y1="30" x2="'+gxp+'" y2="'+groundY+'" stroke="#1e293b" stroke-width="0.5"/>';
      if (gm > 0) s += '<text x="'+gxp+'" y="'+(groundY+15)+'" fill="#475569" font-size="9" text-anchor="middle">'+gm.toFixed(0)+'m</text>';
    }
    var gridSpacingH = gridSpacingM;
    for (var hm = 0; hm <= maxH * 1.5; hm += gridSpacingH) {
      var hyp = groundY - hm * scale;
      if (hyp < 20) break;
      s += '<line x1="'+originX+'" y1="'+hyp+'" x2="580" y2="'+hyp+'" stroke="#1e293b" stroke-width="0.5"/>';
      if (hm > 0) s += '<text x="'+(originX-5)+'" y="'+(hyp+3)+'" fill="#475569" font-size="9" text-anchor="end">'+hm.toFixed(0)+'m</text>';
    }

    // Ground
    s += '<line x1="'+originX+'" y1="'+groundY+'" x2="580" y2="'+groundY+'" stroke="#475569" stroke-width="2"/>';
    for (var hx = originX; hx < 580; hx += 12) {
      s += '<line x1="'+hx+'" y1="'+groundY+'" x2="'+(hx-4)+'" y2="'+(groundY+6)+'" stroke="#475569" stroke-width="1"/>';
    }

    // Trajectory trail
    if (proj.trail.length > 1) {
      s += '<polyline points="';
      for (var ti = 0; ti < proj.trail.length; ti++) {
        var tx = originX + proj.trail[ti][0] * scale;
        var ty = groundY - proj.trail[ti][1] * scale;
        s += tx+','+ty+' ';
      }
      s += '" fill="none" stroke="#3b82f6" stroke-width="2" opacity="0.7"/>';
      // Sample dots
      var dotStep = Math.max(1, Math.floor(proj.trail.length / 20));
      for (var di = 0; di < proj.trail.length; di += dotStep) {
        var dx = originX + proj.trail[di][0] * scale;
        var dy = groundY - proj.trail[di][1] * scale;
        s += '<circle cx="'+dx+'" cy="'+dy+'" r="2.5" fill="#60a5fa" opacity="0.6"/>';
      }
    }

    // Current position
    var cx = originX + proj.x * scale;
    var cy = groundY - proj.y * scale;
    s += '<circle cx="'+cx+'" cy="'+cy+'" r="8" fill="#ef4444" stroke="#fca5a5" stroke-width="1.5"/>';

    // Velocity vector
    var vScaleP = 2;
    var vxP = proj.vx * vScaleP;
    var vyP = -proj.vy * vScaleP;
    if (Math.abs(vxP) > 1 || Math.abs(vyP) > 1) {
      s += '<line x1="'+cx+'" y1="'+cy+'" x2="'+(cx+vxP)+'" y2="'+(cy+vyP)+'" stroke="#22c55e" stroke-width="2" marker-end="url(#arrowGreen)"/>';
      s += '<text x="'+(cx+vxP+8)+'" y="'+(cy+vyP-5)+'" fill="#22c55e" font-size="10">v</text>';
    }

    // Gravity arrow
    if (!proj.landed) {
      s += '<line x1="'+cx+'" y1="'+(cy+12)+'" x2="'+cx+'" y2="'+(cy+35)+'" stroke="#f59e0b" stroke-width="2" marker-end="url(#arrowOrange)"/>';
    }

    // Max height indicator
    if (proj.trail.length > 2) {
      var maxTrailH = 0;
      for (var mi = 0; mi < proj.trail.length; mi++) {
        if (proj.trail[mi][1] > maxTrailH) maxTrailH = proj.trail[mi][1];
      }
      if (maxTrailH > 0.5) {
        var mhy = groundY - maxTrailH * scale;
        s += '<line x1="'+originX+'" y1="'+mhy+'" x2="580" y2="'+mhy+'" stroke="#a78bfa" stroke-width="0.7" stroke-dasharray="5,5" opacity="0.5"/>';
        s += '<text x="582" y="'+(mhy+4)+'" fill="#a78bfa" font-size="10">h='+maxTrailH.toFixed(1)+'m</text>';
      }
    }

    // Range indicator
    if (proj.landed && proj.x > 0) {
      s += '<text x="'+(originX + proj.x * scale / 2)+'" y="'+(groundY+28)+'" fill="#f472b6" font-size="11" text-anchor="middle">Range: '+proj.x.toFixed(1)+' m</text>';
    }

    // Launcher
    var launcherLen = 30;
    var lax = originX + launcherLen * Math.cos(rad(projParams.angle));
    var lay = groundY - launcherLen * Math.sin(rad(projParams.angle));
    s += '<line x1="'+originX+'" y1="'+groundY+'" x2="'+lax+'" y2="'+lay+'" stroke="#94a3b8" stroke-width="4" stroke-linecap="round"/>';

    // Labels
    s += '<text x="15" y="25" fill="#94a3b8" font-size="13" font-weight="600">Projectile Motion</text>';
    s += '<text x="15" y="385" fill="#64748b" font-size="11">\\u03B8 = '+projParams.angle+'\\u00B0  |  v\\u2080 = '+projParams.initialVelocity+' m/s  |  g = '+projParams.gravity.toFixed(1)+' m/s\\u00B2</text>';

    svg.innerHTML = s;
  };

  var renderSpring = function() {
    var s = '';
    s += '<rect width="600" height="400" fill="#0f172a"/>';

    // Grid
    for (var gy = 0; gy < 400; gy += 40) s += '<line x1="0" y1="'+gy+'" x2="600" y2="'+gy+'" stroke="#1e293b" stroke-width="0.5"/>';
    for (var gx = 0; gx < 600; gx += 40) s += '<line x1="'+gx+'" y1="0" x2="'+gx+'" y2="400" stroke="#1e293b" stroke-width="0.5"/>';

    var wallX = 40;
    var centerY = 180;
    var restLength = 180;
    var dispScale = 80;
    var massW = 50, massH = 40;
    var massX = wallX + restLength + spr.disp * dispScale;

    // Wall
    s += '<line x1="'+wallX+'" y1="'+(centerY-60)+'" x2="'+wallX+'" y2="'+(centerY+60)+'" stroke="#475569" stroke-width="3"/>';
    for (var hy = centerY - 55; hy <= centerY + 55; hy += 10) {
      s += '<line x1="'+wallX+'" y1="'+hy+'" x2="'+(wallX-10)+'" y2="'+(hy+8)+'" stroke="#475569" stroke-width="1.5"/>';
    }

    // Equilibrium line
    var eqX = wallX + restLength;
    s += '<line x1="'+eqX+'" y1="'+(centerY-50)+'" x2="'+eqX+'" y2="'+(centerY+50)+'" stroke="#475569" stroke-width="0.8" stroke-dasharray="5,5"/>';
    s += '<text x="'+eqX+'" y="'+(centerY+65)+'" fill="#475569" font-size="10" text-anchor="middle">equilibrium</text>';

    // Spring zigzag
    var springStart = wallX;
    var springEnd = massX;
    var springLen = springEnd - springStart;
    var coils = 12;
    var coilW = springLen / coils;
    var coilH = 20;
    var springPath = 'M'+springStart+','+centerY;
    springPath += ' L'+(springStart + coilW * 0.25)+','+centerY;
    for (var ci = 0; ci < coils; ci++) {
      var cx1 = springStart + coilW * (ci + 0.25);
      var cx2 = springStart + coilW * (ci + 0.5);
      var cx3 = springStart + coilW * (ci + 0.75);
      springPath += ' L'+cx2+','+(centerY - coilH);
      springPath += ' L'+cx3+','+(centerY + coilH);
    }
    springPath += ' L'+springEnd+','+centerY;
    // Color based on compression/extension
    var springColor = Math.abs(spr.disp) < 0.05 ? '#94a3b8' : (spr.disp > 0 ? '#ef4444' : '#3b82f6');
    s += '<path d="'+springPath+'" fill="none" stroke="'+springColor+'" stroke-width="2.5" stroke-linejoin="round"/>';

    // Mass block
    s += '<rect x="'+massX+'" y="'+(centerY - massH/2)+'" width="'+massW+'" height="'+massH+'" rx="4" fill="#1e40af" stroke="#60a5fa" stroke-width="1.5"/>';
    s += '<text x="'+(massX + massW/2)+'" y="'+(centerY+5)+'" fill="#e2e8f0" font-size="12" text-anchor="middle" font-weight="600">'+sprParams.mass.toFixed(1)+'kg</text>';

    // Displacement indicator
    if (Math.abs(spr.disp) > 0.02) {
      var dispDir = spr.disp > 0 ? 1 : -1;
      var arrowY = centerY + massH/2 + 25;
      s += '<line x1="'+eqX+'" y1="'+arrowY+'" x2="'+(massX + massW/2)+'" y2="'+arrowY+'" stroke="#a78bfa" stroke-width="2" marker-end="url(#arrowPurple)"/>';
      s += '<text x="'+((eqX + massX + massW/2)/2)+'" y="'+(arrowY + 15)+'" fill="#a78bfa" font-size="10" text-anchor="middle">x = '+spr.disp.toFixed(3)+' m</text>';
    }

    // Force arrow (spring force)
    var force = -(sprParams.springConstant) * spr.disp;
    var forceScale = 1.5;
    if (Math.abs(force) > 0.3) {
      var forceLen = force * forceScale;
      var forceY = centerY - massH/2 - 15;
      s += '<line x1="'+(massX + massW/2)+'" y1="'+forceY+'" x2="'+(massX + massW/2 + forceLen)+'" y2="'+forceY+'" stroke="#f59e0b" stroke-width="2.5" marker-end="url(#arrowOrange)"/>';
      s += '<text x="'+(massX + massW/2 + forceLen/2)+'" y="'+(forceY - 8)+'" fill="#f59e0b" font-size="10" text-anchor="middle">F = '+force.toFixed(1)+' N</text>';
    }

    // Velocity arrow
    if (Math.abs(spr.vel) > 0.05) {
      var velLen = spr.vel * 25;
      var velY = centerY;
      s += '<line x1="'+(massX + massW)+'" y1="'+velY+'" x2="'+(massX + massW + velLen)+'" y2="'+velY+'" stroke="#22c55e" stroke-width="2" marker-end="url(#arrowGreen)"/>';
    }

    // Displacement-time graph
    var graphX = 60, graphY = 280, graphW = 480, graphH = 100;
    s += '<rect x="'+graphX+'" y="'+graphY+'" width="'+graphW+'" height="'+graphH+'" fill="#0f172a" stroke="#334155" stroke-width="1" rx="4"/>';
    s += '<line x1="'+graphX+'" y1="'+(graphY + graphH/2)+'" x2="'+(graphX + graphW)+'" y2="'+(graphY + graphH/2)+'" stroke="#334155" stroke-width="0.5"/>';
    s += '<text x="'+(graphX - 5)+'" y="'+(graphY + graphH/2 + 4)+'" fill="#475569" font-size="9" text-anchor="end">0</text>';
    s += '<text x="'+(graphX + graphW/2)+'" y="'+(graphY + graphH + 15)+'" fill="#475569" font-size="10" text-anchor="middle">Displacement vs Time</text>';

    if (spr.history.length > 1) {
      var tMin = spr.history[0][0];
      var tMax = spr.history[spr.history.length - 1][0];
      var tRange = Math.max(tMax - tMin, 0.1);
      var maxDisp = sprParams.initialDisplacement * 1.1;
      s += '<polyline points="';
      for (var hi = 0; hi < spr.history.length; hi++) {
        var hx = graphX + ((spr.history[hi][0] - tMin) / tRange) * graphW;
        var hy = graphY + graphH/2 - (spr.history[hi][1] / maxDisp) * (graphH/2);
        s += hx+','+hy+' ';
      }
      s += '" fill="none" stroke="#a78bfa" stroke-width="1.5"/>';
    }

    // Labels
    s += '<text x="15" y="25" fill="#94a3b8" font-size="13" font-weight="600">Spring-Mass System</text>';

    svg.innerHTML = s;
  };

  var render = function() {
    if (activeTab === 'pendulum') renderPendulum();
    else if (activeTab === 'projectile') renderProjectile();
    else renderSpring();
  };

  // === Readout ===
  var updateReadout = function() {
    var pos, vel, acc;
    if (activeTab === 'pendulum') {
      var L = pendParams.length;
      var px = L * Math.sin(pend.theta);
      var py = L * Math.cos(pend.theta);
      var vxP = L * pend.omega * Math.cos(pend.theta);
      var vyP = -L * pend.omega * Math.sin(pend.theta);
      var alpha = -(pendParams.gravity/L)*Math.sin(pend.theta) - pendParams.damping*pend.omega;
      var axP = L*(alpha*Math.cos(pend.theta) - pend.omega*pend.omega*Math.sin(pend.theta));
      var ayP = -L*(alpha*Math.sin(pend.theta) + pend.omega*pend.omega*Math.cos(pend.theta));
      pos = '(' + fmt(px) + ', ' + fmt(py) + ') m';
      vel = '(' + fmt(vxP) + ', ' + fmt(vyP) + ') m/s  |' + fmt(mag(vxP,vyP)) + '|';
      acc = '(' + fmt(axP) + ', ' + fmt(ayP) + ') m/s\\u00B2';
    } else if (activeTab === 'projectile') {
      pos = '(' + fmt(proj.x) + ', ' + fmt(proj.y) + ') m';
      vel = '(' + fmt(proj.vx) + ', ' + fmt(proj.vy) + ') m/s  |' + fmt(mag(proj.vx,proj.vy)) + '|';
      acc = '(0.000, ' + fmt(-projParams.gravity) + ') m/s\\u00B2';
    } else {
      var a = -(sprParams.springConstant/sprParams.mass)*spr.disp - (sprParams.damping/sprParams.mass)*spr.vel;
      pos = fmt(spr.disp) + ' m';
      vel = fmt(spr.vel) + ' m/s';
      acc = fmt(a) + ' m/s\\u00B2';
    }
    document.getElementById('val-pos').textContent = pos;
    document.getElementById('val-vel').textContent = vel;
    document.getElementById('val-acc').textContent = acc;
    document.getElementById('val-time').textContent = time.toFixed(3) + ' s';

    // Detail value
    var detail = '';
    if (activeTab === 'pendulum') {
      detail = '\\u03B8 = ' + deg(pend.theta).toFixed(2) + '\\u00B0  |  \\u03C9 = ' + pend.omega.toFixed(3) + ' rad/s';
    } else if (activeTab === 'projectile') {
      var curMaxH = 0;
      for (var i = 0; i < proj.trail.length; i++) if (proj.trail[i][1] > curMaxH) curMaxH = proj.trail[i][1];
      detail = 'Max H: ' + curMaxH.toFixed(2) + ' m  |  Range: ' + (proj.landed ? proj.x.toFixed(2) : '...') + ' m';
    } else {
      var energy = 0.5*sprParams.springConstant*spr.disp*spr.disp + 0.5*sprParams.mass*spr.vel*spr.vel;
      var freq = Math.sqrt(sprParams.springConstant/sprParams.mass)/(2*Math.PI);
      detail = 'E = ' + energy.toFixed(3) + ' J  |  f = ' + freq.toFixed(2) + ' Hz';
    }
    document.getElementById('val-detail').textContent = detail;
  };

  // === Animation loop ===
  var loop = function(ts) {
    if (!running) { lastFrame = null; return; }
    if (lastFrame === null) { lastFrame = ts; animId = requestAnimationFrame(loop); return; }
    var elapsed = Math.min((ts - lastFrame) / 1000, 0.05) * speed;
    lastFrame = ts;

    var steps = Math.ceil(elapsed / DT);
    var stepDt = elapsed / steps;
    for (var i = 0; i < steps; i++) {
      stepPhysics(stepDt);
    }

    render();
    updateReadout();
    animId = requestAnimationFrame(loop);
  };

  // === Controls ===
  var updatePlayBtn = function() {
    var btn = document.getElementById('btn-play');
    btn.textContent = running ? '\\u23F8 Pause' : '\\u25B6 Play';
    btn.className = 'btn ' + (running ? 'btn-pause' : 'btn-play');
  };

  document.getElementById('btn-play').addEventListener('click', function() {
    running = !running;
    updatePlayBtn();
    if (running) { lastFrame = null; animId = requestAnimationFrame(loop); }
  });

  document.getElementById('btn-reset').addEventListener('click', function() {
    running = false;
    if (animId) cancelAnimationFrame(animId);
    resetCurrent();
  });

  document.getElementById('speed-slider').addEventListener('input', function(e) {
    speed = parseFloat(e.target.value);
    document.getElementById('speed-val').textContent = speed.toFixed(1) + 'x';
  });

  // Tab switching
  var tabs = document.querySelectorAll('.tab-btn');
  tabs.forEach(function(tab) {
    tab.addEventListener('click', function() {
      tabs.forEach(function(t) { t.classList.remove('active'); });
      tab.classList.add('active');
      activeTab = tab.getAttribute('data-tab');
      // Show/hide param panels
      document.querySelectorAll('.param-panel').forEach(function(p) { p.style.display = 'none'; });
      document.getElementById('params-' + activeTab).style.display = 'flex';
      running = false;
      if (animId) cancelAnimationFrame(animId);
      resetCurrent();
    });
  });

  // === Parameter sliders ===
  // Pendulum
  document.getElementById('pend-length').addEventListener('input', function(e) {
    pendParams.length = parseFloat(e.target.value);
    document.getElementById('pend-length-val').textContent = pendParams.length.toFixed(1);
    if (!running) { initPendulum(); render(); updateReadout(); }
  });
  document.getElementById('pend-gravity').addEventListener('input', function(e) {
    pendParams.gravity = parseFloat(e.target.value);
    document.getElementById('pend-gravity-val').textContent = pendParams.gravity.toFixed(1);
    if (!running) { initPendulum(); render(); updateReadout(); }
  });
  document.getElementById('pend-angle').addEventListener('input', function(e) {
    pendParams.initialAngle = parseFloat(e.target.value);
    document.getElementById('pend-angle-val').textContent = pendParams.initialAngle;
    if (!running) { initPendulum(); render(); updateReadout(); }
  });

  // Projectile
  document.getElementById('proj-angle').addEventListener('input', function(e) {
    projParams.angle = parseFloat(e.target.value);
    document.getElementById('proj-angle-val').textContent = projParams.angle;
    if (!running) { initProjectile(); render(); updateReadout(); }
  });
  document.getElementById('proj-velocity').addEventListener('input', function(e) {
    projParams.initialVelocity = parseFloat(e.target.value);
    document.getElementById('proj-velocity-val').textContent = projParams.initialVelocity;
    if (!running) { initProjectile(); render(); updateReadout(); }
  });
  document.getElementById('proj-gravity').addEventListener('input', function(e) {
    projParams.gravity = parseFloat(e.target.value);
    document.getElementById('proj-gravity-val').textContent = projParams.gravity.toFixed(1);
    if (!running) { initProjectile(); render(); updateReadout(); }
  });

  // Spring
  document.getElementById('spr-k').addEventListener('input', function(e) {
    sprParams.springConstant = parseFloat(e.target.value);
    document.getElementById('spr-k-val').textContent = sprParams.springConstant;
    if (!running) { initSpring(); render(); updateReadout(); }
  });
  document.getElementById('spr-mass').addEventListener('input', function(e) {
    sprParams.mass = parseFloat(e.target.value);
    document.getElementById('spr-mass-val').textContent = sprParams.mass.toFixed(1);
    if (!running) { initSpring(); render(); updateReadout(); }
  });
  document.getElementById('spr-disp').addEventListener('input', function(e) {
    sprParams.initialDisplacement = parseFloat(e.target.value);
    document.getElementById('spr-disp-val').textContent = sprParams.initialDisplacement.toFixed(1);
    if (!running) { initSpring(); render(); updateReadout(); }
  });

  // === Arrow markers (injected into SVG defs) ===
  var addDefs = function() {
    var defs = document.createElementNS('http://www.w3.org/2000/svg', 'defs');
    defs.innerHTML = '<marker id="arrowGreen" viewBox="0 0 10 10" refX="9" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse"><path d="M 0 0 L 10 5 L 0 10 z" fill="#22c55e"/></marker>'
      + '<marker id="arrowOrange" viewBox="0 0 10 10" refX="9" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse"><path d="M 0 0 L 10 5 L 0 10 z" fill="#f59e0b"/></marker>'
      + '<marker id="arrowPurple" viewBox="0 0 10 10" refX="9" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse"><path d="M 0 0 L 10 5 L 0 10 z" fill="#a78bfa"/></marker>';
    svg.appendChild(defs);
  };
  addDefs();

  // === Init ===
  initPendulum();
  render();
  updateReadout();
  updatePlayBtn();
})();
`

import { h, Fragment } from 'plaited'
