const paramSlider = (id: string, label: string, min: number, max: number, step: number, value: number, valId: string, valDisplay: string) =>
  h('div', { class: 'param-row' },
    h('label', {}, label),
    h('input', { type: 'range', id, min: String(min), max: String(max), step: String(step), value: String(value) }),
    h('span', { class: 'pval', id: valId }, valDisplay),
  )

export const renderPage = (): string => {
  const template = h(Fragment, {},
    h('html', { lang: 'en' },
      h('head', {},
        h('meta', { charset: 'UTF-8' }),
        h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
        h('title', {}, "Newton's Laws Simulator"),
        h('style', {}, styles),
      ),
      h('body', {},
        h('div', { class: 'container' },
          h('h1', {}, "Newton's Laws Simulator"),
          h('p', { class: 'subtitle' }, 'Interactive physics — pendulum, projectile motion, spring-mass'),

          // Tabs
          h('div', { class: 'tabs' },
            h('button', { class: 'tab-btn active', 'data-tab': 'pendulum' }, 'Pendulum'),
            h('button', { class: 'tab-btn', 'data-tab': 'projectile' }, 'Projectile'),
            h('button', { class: 'tab-btn', 'data-tab': 'spring' }, 'Spring-Mass'),
          ),

          // SVG Canvas
          h('div', { class: 'canvas-wrap' },
            h('svg', { id: 'sim-canvas', viewBox: '0 0 600 400', xmlns: 'http://www.w3.org/2000/svg' }),
          ),

          // Controls
          h('div', { class: 'controls' },
            h('button', { class: 'btn btn-play', id: 'btn-play' }, '\u25B6 Play'),
            h('button', { class: 'btn btn-reset', id: 'btn-reset' }, '\u21BB Reset'),
            h('div', { class: 'speed-group' },
              h('label', {}, 'Speed'),
              h('input', { type: 'range', id: 'speed-slider', min: '0.1', max: '3', step: '0.1', value: '1' }),
              h('span', { class: 'speed-val', id: 'speed-val' }, '1.0x'),
            ),
          ),

          // Readout values
          h('div', { class: 'values-grid' },
            h('div', { class: 'value-card pos' },
              h('div', { class: 'label' }, 'Position'),
              h('div', { class: 'val', id: 'val-pos' }, '—'),
            ),
            h('div', { class: 'value-card vel' },
              h('div', { class: 'label' }, 'Velocity'),
              h('div', { class: 'val', id: 'val-vel' }, '—'),
            ),
            h('div', { class: 'value-card acc' },
              h('div', { class: 'label' }, 'Acceleration'),
              h('div', { class: 'val', id: 'val-acc' }, '—'),
            ),
            h('div', { class: 'value-card' },
              h('div', { class: 'label' }, 'Time'),
              h('div', { class: 'val', id: 'val-time' }, '—'),
            ),
            h('div', { class: 'value-card detail' },
              h('div', { class: 'label' }, 'Details'),
              h('div', { class: 'val', id: 'val-detail' }, '—'),
            ),
          ),

          // Pendulum params
          h('div', { class: 'param-panel show', id: 'params-pendulum', style: 'display: flex' },
            paramSlider('pend-length', 'Length (m)', 0.5, 4, 0.1, 2, 'pend-length-val', '2.0'),
            paramSlider('pend-gravity', 'Gravity (m/s\u00B2)', 0.5, 30, 0.1, 9.81, 'pend-gravity-val', '9.8'),
            paramSlider('pend-angle', 'Angle (\u00B0)', 5, 170, 1, 45, 'pend-angle-val', '45'),
          ),

          // Projectile params
          h('div', { class: 'param-panel', id: 'params-projectile' },
            paramSlider('proj-angle', 'Angle (\u00B0)', 5, 85, 1, 45, 'proj-angle-val', '45'),
            paramSlider('proj-velocity', 'Velocity (m/s)', 5, 50, 1, 20, 'proj-velocity-val', '20'),
            paramSlider('proj-gravity', 'Gravity (m/s\u00B2)', 0.5, 30, 0.1, 9.81, 'proj-gravity-val', '9.8'),
          ),

          // Spring params
          h('div', { class: 'param-panel', id: 'params-spring' },
            paramSlider('spr-k', 'k (N/m)', 1, 50, 1, 15, 'spr-k-val', '15'),
            paramSlider('spr-mass', 'Mass (kg)', 0.5, 10, 0.1, 2, 'spr-mass-val', '2.0'),
            paramSlider('spr-disp', 'x\u2080 (m)', 0.5, 3, 0.1, 1.5, 'spr-disp-val', '1.5'),
          ),

          // Client script
          h('script', {}, clientScript),
        ),
      ),
    ),
  )

  const ssr = createSSR()
  const result = ssr(template)
  return `<!DOCTYPE html>${result}`
}

import { renderPage } from './renderer'

const html = renderPage()

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (url.pathname === '/' || url.pathname === '/index.html') {
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (url.pathname === '/api/presets') {
      const file = Bun.file('./data/presets.json')
      return new Response(file, {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Newton's Laws Simulator running at http://localhost:${server.port}`)
